export const EXAM_FAQS: Record<string, Array<{ question: string; answer: string }>> = {
  'neet': [
    { question: 'What is the eligibility criteria for NEET UG?', answer: 'Candidates must be at least 17 years old as of December 31 of the admission year. There is no upper age limit for NEET (as of the latest NMC rule). Academic requirement: 50% marks in Physics, Chemistry, and Biology (PCB) in the qualifying examination for the general category; 40% for reserved categories. Students appearing in Class 12 can also apply.' },
    { question: 'What is the exam pattern for NEET?', answer: 'NEET consists of 200 multiple-choice questions (180 mandatory + 10 optional), to be answered within 3 hours and 20 minutes. The paper covers three subjects: Physics (50 questions), Chemistry (50 questions), and Biology (100 questions — 90 mandatory + 10 optional). Each correct answer earns 4 marks; 1 mark is deducted for each wrong answer.' },
    { question: 'How many attempts are allowed for NEET?', answer: 'There is no limit on the number of attempts for NEET, provided the candidate meets the age and eligibility criteria. However, the upper age limit has been a subject of judicial review — check the latest NMC guidelines before applying.' },

    { question: 'Is the NEET 2026 syllabus changed from 2025?', answer: 'No major syllabus changes have been announced for NEET 2026 by NTA. The syllabus remains Physics, Chemistry, and Biology (Botany + Zoology) based on the NCERT Class 11 and 12 curriculum. However, the exam mode (CBT), number of questions (200, answer 180), and marking scheme (+4 / -1) remain the same. Keep checking the official NTA website (nta.ac.in) for any updates.' },
    { question: 'What is the expected NEET 2026 registration date and fee?', answer: 'NEET 2026 registration is expected to open in February–March 2026 through the NTA website (nta.ac.in). The application fee is expected to be Rs. 1700 for general category and Rs. 1000 for SC/ST/OBC candidates (last year fee). The exam is likely to be held in May 2026. Watch nta.ac.in and the official NEET website for the exact notification.' },
    { question: 'How is NEET normalized across different shifts?', answer: 'NTA uses an equipercentile method to normalize NEET scores across different exam shifts. Your raw score is converted into a percentile score, and the rank list is prepared using these normalized scores so that students in harder or easier shifts are treated fairly.' },
    { question: 'What is a good NEET score for MBBS admission in 2026?', answer: 'For general category candidates, 600+ out of 720 is considered a safe score for top government medical colleges (MBBS). Scores of 550–600 can get government seats in state-level colleges. Scores of 450–550 are competitive for deemed universities and private colleges. Scores above 150 ( cutoff) qualify for the exam, but admission depends on the rank and seat matrix in each counselling round.' },
    { question: 'neet 2026 registration date', answer: 'NEET 2026 registration is expected to open in February–March 2026 through the official NTA website (nta.ac.in). Candidates must apply online at nta.ac.in or neet.ntaonline.in. The application window typically stays open for 4–6 weeks. The NEET 2026 exam is expected to be held in May 2026. Keep checking nta.ac.in for the exact notification and dates.' },
    { question: 'neet 2026 expected cutoff', answer: 'NEET 2026 expected cutoffs (out of 720): For top government MBBS seats (AIIMS, top state colleges), a score of 600+ is generally safe for general category. Scores of 550–600 can secure government seats in state-level colleges through AIQ and state counselling. Scores of 450–550 are competitive for deemed universities and private medical colleges. The exact cutoff varies each year based on exam difficulty, number of candidates, and seat matrix.' },
    { question: 'neet 2026 chapter wise weightage', answer: 'NEET 2026 chapter-wise weightage follows a similar pattern to previous years: Biology carries the highest weightage at ~50% of the paper — Human Physiology (~9%), Genetics & Evolution (~8%), and Ecology (~7%) are the top-scoring chapters. Physics and Chemistry each carry ~25%. In Physics, Electrodynamics (Electrostatics, Current Electricity, Magnetism) combined carries ~20%. In Chemistry, Organic Chemistry and Inorganic Chemistry together carry the majority of questions. Focus revision on NCERT Biology lines first — they cover over 85% of the Biology section.' },
    { question: 'neet 2026 result date', answer: 'NEET 2026 result is expected to be declared in July 2026, typically within 3–4 weeks after the exam. The exact date is announced by NTA closer to the exam. Candidates can check their result on the official NTA website (nta.ac.in) using their application number and date of birth. The result includes the raw score, percentile, All India Rank, and category-wise cutoff scores.' },  ],
  'fmge': [
    { question: 'What is FMGE and who needs to take it?', answer: 'FMGE (Foreign Medical Graduate Examination) is a mandatory screening test conducted by the National Board of Examinations (NBE) for Indian citizens (or OCI cardholders) who have obtained their primary medical qualification from a medical college outside India. If you have an MBBS degree from a country like China, Ukraine, Russia, Philippines, Georgia, Nepal, Bangladesh, etc., you must clear FMGE to be eligible to practice medicine in India or apply for postgraduate studies. The exam is held twice a year (June and December sessions). Without passing FMGE, you cannot get a licence to practice as a doctor in India.' },
    { question: 'What is the FMGE exam pattern?', answer: 'FMGE consists of 300 multiple-choice questions divided into two parts: Part A (150 questions) covering Anatomy, Physiology, Biochemistry, Pathology, Pharmacology, Microbiology, and Forensic Medicine; Part B (150 questions) covering Ophthalmology, Otorhinolaryngology, Preventive & Social Medicine, Medicine, Surgery, Obstetrics & Gynecology, and Pediatrics. Each correct answer carries 1 mark; 0.25 marks are deducted for each wrong answer. The exam is conducted online (CBT) over 2 hours and 30 minutes. The pass mark is 150 out of 300 (50%).' },
    { question: 'How tough is FMGE and how should I prepare?', answer: 'FMGE has a historically low pass rate — typically 10–20% of candidates clear it on any given attempt. The exam covers all 19 subjects from the MBBS curriculum, making it comprehensive and challenging for students whose foreign medical programmes may not have covered all Indian syllabus topics in equal depth. Candidates must score 150+/300 to pass. Most candidates take 2–4 attempts before clearing. StudyRoadmap covers all FMGE subjects with topic-wise notes designed for screening exam preparation.' },
  ],
  'jeemain': [
    { question: 'What is JEE Main and who conducts it?', answer: 'JEE Main (Joint Entrance Examination — Main) is India\'s premier engineering entrance exam conducted by NTA (National Testing Agency) in computer-based mode. It is the first of the two-stage JEE examination system — JEE Main qualifies candidates for JEE Advanced (the exam for admission to IITs). JEE Main is also used for direct admission to NITs (National Institutes of Technology), IIITs (Indian Institutes of Information Technology), and other Centrally Funded Technical Institutions (CFTIs). Over 1 million students appear for JEE Main each year across two sessions (January and April). The exam has two papers: Paper 1 (B.E./B.Tech) and Paper 2 (B.Arch/B.Planning). The best of two sessions is used for the final merit list and JoSAA counselling.' },
    { question: 'What is the eligibility for JEE Main?', answer: 'Candidates must have passed Class 12 or be appearing in the current academic year. There is no minimum aggregate requirement for appearing in JEE Main, but for admission to NITs, IIITs, and CFTIs, candidates typically need 75% or above (or be in the top 20 percentile of their board). For SC/ST candidates, the requirement is 65%. There is no age limit for JEE Main. Candidates must have studied Physics, Chemistry, and Mathematics (PCM) in Class 12. The board must be recognized by the Government of India.' },
    { question: 'What is the JEE Main exam pattern?', answer: 'JEE Main Paper 1 (B.E./B.Tech) consists of 90 multiple-choice questions across three sections: Physics (30 questions), Chemistry (30 questions), and Mathematics (30 questions). Each subject has Section A (25 MCQs) and Section B (5 Numerical Value questions — candidates attempt any 5 of the 10 questions). Each MCQ carries 4 marks with -1 for wrong answers; numerical questions carry 4 marks with no negative marking. Total: 300 marks, 3 hours. The exam is conducted online (CBT) in English and 12 regional languages.' },
    { question: 'How many attempts are allowed for JEE Main?', answer: 'JEE Main is conducted twice a year (January Session and April Session). A candidate can appear for both sessions in the same calendar year and the better of the two NTA scores is used for the final merit list. There is no upper age limit and no cap on the total number of attempts across years. However, for JEE Advanced eligibility, only the top 2,50,000 rankers from JEE Main are considered, and candidates must meet the 75% aggregate requirement (or top 20 percentile of their board) in Class 12.' },
    { question: 'What is JoSAA counselling and how does it work?', answer: 'JoSAA (Joint Seat Allocation Authority) conducts centralized counselling for admission to 118 NITs, IIITs, and CFTIs after JEE Main results are declared. The process: (1) Register on josaa.nic.in using JEE Main roll number and rank, (2) Fill in preferred choices of institute and branch, (3) Seat allocation happens in 6 rounds based on rank, category, and choices, (4) Accept or upgrade allocated seat in each round. The seat acceptance fee is ₹35,000 for General/OBC and ₹18,000 for SC/ST/PwD. After seat allocation, candidates report to the institute for document verification and admission confirmation.' },
    { question: 'What is the JEE Main 2026 Session 2 exam date and how to download the admit card?', answer: 'JEE Main 2026 Session 2 is scheduled for April 2–8, 2026 (exact shift dates vary by candidate). The Session 2 admit card was released on March 29, 2026. To download: visit jeemain.ntaonline.in, log in with Application Number and Password, and download the PDF. Candidates must carry the printed admit card and a valid photo ID (Aadhaar/Passport/PAN) to the exam centre. The exam is conducted in two shifts: Morning (9:00 AM–12:00 PM) and Afternoon (3:00 PM–6:00 PM). The result for Session 2 is expected on April 20, 2026.' },
    { question: 'How is JEE Main normalized across sessions?', answer: 'NTA uses an equipercentile method to normalize JEE Main scores across different exam sessions and shifts. Since the exam is conducted multiple times and in multiple shifts, raw scores alone are not comparable. NTA converts raw scores into percentile scores (0–100) for each session, then uses the best of two sessions for the final rank list. This ensures fairness — students who appeared in a tougher shift are not disadvantaged compared to those who got an easier shift.' },
    { question: 'What is the expected cut-off for JEE Main 2026 for NIT admission?', answer: 'For General category, a JEE Main percentile of 95+ (approximately 180+ marks out of 300) is typically needed for top NIT branches like Computer Science. For OBC category, 75+ percentile (~140–160 marks) is competitive. For SC/ST, 50+ percentile (~70–100 marks) can secure admission in many NITs. The exact cut-off varies by institute, branch, home state quota, and session difficulty. The qualifying cut-off (for JEE Advanced eligibility) is lower — around 82.5 percentile for General, 55 for OBC, 37.5 for SC, and 27.5 for ST.' },
    { question: 'How do I challenge the JEE Main answer key?', answer: 'After each JEE Main session, NTA releases a provisional answer key on its official website (nta.ac.in / jeemain.ntaonline.in). If you find an error: (1) Login to the objection portal during the objection window (typically 3–5 days after the answer key is released), (2) Select the question ID you want to challenge, (3) Pay ₹200 per question as the challenge fee (online payment), (4) NTA reviews all objections and releases the Final Answer Key, (5) The final answer key is used for calculating the official result. No challenges are accepted after the window closes — ensure you act within the specified dates.' },
    { question: 'jee main 2026 answer key', answer: 'The JEE Main 2026 answer key is released by NTA typically 2–3 days after the completion of each session exam. For Session 1 (January 21–29, 2026), the answer key was released in February 2026. For Session 2 (April 2–8, 2026), the answer key is expected in April 2026. Candidates can download the official answer key from the NTA website (jeemain.ntaonline.in or nta.ac.in) — it is available as a subject-wise PDF. Candidates who find discrepancies can raise objections within the specified window (3–5 days) by paying ₹200 per question. The final answer key, after considering objections, is used for calculating the official result declared on April 20, 2026 for Session 2.' },
    { question: 'jee main 2026 result date', answer: 'JEE Main 2026 Session 1 result was declared in February 2026. Session 2 result is expected to be declared on April 20, 2026 per the official NTA schedule. Candidates can check their result on the official NTA website (nta.ac.in or jeemain.ntaonline.in) using their Application Number and Date of Birth. The result includes: raw score (out of 300), NTA percentile score, and All India Rank (AIR). The final JoSAA counselling uses the best of Session 1 and Session 2 percentile scores. Keep your Application Number and Password ready before the result date to avoid last-minute issues.' },
  ],
  'jee-barch': [
    { question: 'What is JEE Main Paper 3 (B.Arch) and who is it for?', answer: 'JEE Main Paper 3 (B.Arch) is the architecture entrance exam conducted as part of JEE Main for admission to B.Arch and B.Planning programmes in NITs, SPA, and other Centrally Funded Technical Institutions. While B.E./B.Tech admissions use Paper 1 (PCM), B.Arch admissions require Paper 3 which includes Mathematics, Aptitude Test, and Drawing Test. Candidates interested in architectural design, urban planning, and building design should appear for Paper 3 in addition to or instead of Paper 1. After qualifying JEE Main B.Arch, candidates must also appear for a separate Architecture Aptitude Test (AAT) conducted by IISc Bangalore for IIT admissions.' },
    { question: 'What is the JEE Main B.Arch exam pattern?', answer: 'JEE Main B.Arch (Paper 3) consists of three parts: Part I — Mathematics (20 MCQs + 5 Numerical Value questions, 100 marks total), Part II — General Aptitude Test (50 MCQs, 200 marks, covering areas like analytical reasoning, visual reasoning, logical thinking, design awareness), and Part III — Drawing Test (2 questions, 100 marks, testing sketch composition, architectural awareness, and freehand drawing). The exam is conducted offline (pen-and-paper) for Part III (Drawing sheet) and Part I-II on CBT. Total duration is 3 hours. Each correct answer carries 4 marks; 1 mark is deducted for wrong MCQ answers.' },
    { question: 'How does B.Arch admission through JEE Main work?', answer: 'After qualifying JEE Main (Paper 3), candidates participate in JoSAA counselling for seat allocation to NITs, SPAs, and other CFTIs offering B.Arch. The cutoff ranks for B.Arch are generally lower than B.Tech — a JEE Main rank of 10,000–15,000 is competitive for top NITs offering Architecture. The top architecture colleges in India include: SPA Delhi, NIT Hamirpur (Architecture), NIT Tiruchirappalli, School of Planning and Architecture Vijayawada, and CEPT Ahmedabad. For IITs offering B.Arch, candidates must qualify JEE Advanced AAT in addition to JEE Advanced.' },
  ],
  'sat': [
    { question: 'What is the SAT and which universities require it?', answer: 'The SAT (Scholastic Assessment Test) is a standardised entrance exam used primarily for undergraduate admissions to universities in the United States and other countries. It is developed and administered by the College Board (ETS). The SAT tests reading, writing, and mathematics skills — the knowledge and skills students are expected to have acquired in high school. Most US universities require SAT or ACT scores as part of the undergraduate application. The SAT is also accepted by universities in Canada, the UK, Australia, Singapore, and other countries as part of international admissions. It is typically taken by students in Classes 10, 11, or 12.' },
    { question: 'What is the SAT exam pattern?', answer: 'The SAT (Digital, 2023 onwards) consists of two sections: Reading and Writing (54 questions, 64 minutes) and Math (44 questions, 70 minutes). Total duration is 2 hours 14 minutes. The Reading and Writing section tests comprehension, vocabulary in context, and grammar. The Math section covers algebra, problem-solving, advanced math, and data analysis — with both calculator-permitted and no-calculator portions. Each section is scored 200–800, for a total score of 400–1600. The SAT is now conducted digitally at designated test centres. The College Board has also introduced the SAT School Day programme — students can take the SAT at their own school during the academic year.' },
    { question: 'What SAT score do I need for top universities?', answer: 'Most US universities publish median SAT scores for admitted students. For Ivy League and top US universities (Harvard, Stanford, MIT, etc.), a SAT score of 1500+ out of 1600 is typical for admitted students. For top 20 universities, 1450+ is generally competitive. For other selective universities, 1300+ is often sufficient. Many universities have become test-optional post-2020 — meaning SAT scores are not required but submitting them can strengthen your application. For international students, a strong SAT score (1400+) significantly strengthens your application. Some universities also award merit scholarships based on SAT scores.' },
  ],
  'act': [
    { question: 'What is the ACT and how does it compare to the SAT?', answer: 'The ACT (American College Testing) is a standardised entrance exam for US university admissions, like the SAT but with some key differences. The ACT tests English, Mathematics, Reading, Science, and an optional Writing test. It is accepted by all US universities and many worldwide. While SAT has a stronger emphasis on vocabulary and reading, ACT has a dedicated Science section — making it more suitable for students who excel in science or prefer a more straightforward test format. Both tests are equally accepted by US universities — there is no preference for one over the other. Most Indian students take both and submit the better score.' },
    { question: 'What is the ACT exam pattern?', answer: 'The ACT consists of 4 mandatory sections plus an optional Writing test: English (75 questions, 45 minutes — grammar, punctuation, sentence structure), Mathematics (60 questions, 60 minutes — algebra, geometry, trigonometry), Reading (40 questions, 35 minutes — 4 passages, reading comprehension), Science (40 questions, 35 minutes — data interpretation, research summaries, conflicting hypotheses). Each section is scored 1–36; the composite score is the average of the four sections. With the optional Writing test, an additional score of 2–12 is reported. Total duration is 2 hours 55 minutes (or 3 hours 35 minutes with Writing).' },
    { question: 'ACT vs SAT — which should I take?', answer: 'Both are equally accepted by universities — choose based on your strengths: Take ACT if you excel in science and prefer direct, fact-based questions; prefer less vocabulary dependence; are strong in time management under pressure. Take SAT if you are a strong reader with good vocabulary; prefer reasoning-based questions over fact-based; do better with the SAT\'s calculator policy (more focused sections). Many Indian students take both — submit the higher score. Both tests are accepted for international admissions to the US. If you struggle with science, ACT\'s Science section can hurt your composite score — in that case, SAT may be better. Register for both if possible and take the one that goes better.' },
  ],
  'jeeadvanced': [
    { question: 'Who is eligible to appear for JEE Advanced?', answer: 'Only the top 2,50,000 rankers in JEE Main (including all categories) are eligible to appear for JEE Advanced. Additionally, candidates must be among the top 20 percentile of their respective board examination. Age limit: candidates should have been born on or after October 1, 1998 (5-year relaxation for SC/ST/PwD candidates).' },
    { question: 'What is the JEE Advanced exam pattern?', answer: 'JEE Advanced consists of multiple papers (Paper 1 and Paper 2, each of 3 hours). The question paper comprises three subjects: Physics, Chemistry, and Mathematics. Questions are a mix of MCQs, numerical answer type (NAT), and comprehension/match columns. The marking scheme varies each year and is detailed in the Information Brochure released annually.' },
    { question: 'What is theSylabus overlap between JEE Main and JEE Advanced?', answer: 'The JEE Advanced syllabus is broadly similar to JEE Main but goes deeper and includes additional topics. Key additions in JEE Advanced include: General Organic Chemistry (detailed), Chemical Thermodynamics (extended), Electronic Devices (additional topics), and more complex problem-solving expectations across all three subjects.' },
  ],
  'upsc': [
    { question: 'What is the eligibility for UPSC Civil Services Examination?', answer: 'Candidates must hold a degree (graduation in any discipline) from a recognised university. Age limit: 21 to 32 years as of August 1 of the exam year for the general category. Attempts allowed: 6 for general category; 9 for OBC; unlimited for SC/ST (until the age limit is reached. PwD candidates get additional attempts based on their category.' },
    { question: 'What are the stages of the UPSC exam?', answer: 'The UPSC Civil Services Examination has three stages: (1) Preliminary Examination (Objective MCQs — General Studies Paper I and CSAT Paper II), (2) Mains Examination (Conventional/Descriptive — 9 papers including an Essay, four General Studies, two optional papers, and two language papers), and (3) Personality Test/Interview (275 marks). The final merit list is based on Mains + Interview.' },
    { question: 'What is the exam pattern for UPSC Prelims?', answer: 'UPSC Prelims consists of two objective-type papers: General Studies Paper I (200 marks, 80 questions on history, geography, polity, economy, science, environment, and current affairs) and CSAT Paper II (200 marks, 80 questions on comprehension, logical reasoning, and analytical ability). CSAT is qualifying in nature (33% threshold). Both papers are of 2 hours each. Negative marking applies: 0.66 marks deducted for each wrong answer.' },

    { question: 'What is the age limit for UPSC CSE 2026?', answer: 'The age limit for UPSC CSE 2026 is 21 to 32 years as of August 1, 2026 for the general category. Age relaxation: 3 years for OBC, 5 years for SC/ST. Candidates must have a graduation degree in any discipline from a recognized university.' },
    { question: 'How many attempts are allowed for UPSC CSE 2026?', answer: 'General category: 6 attempts; OBC: 9 attempts; SC/ST: unlimited until age limit. The exam has three stages — Prelims (objective), Mains (descriptive), and Interview — and a candidate typically needs 2–3 attempts to clear all stages.' },
    { question: 'What is the expected UPSC CSE 2026 notification date?', answer: 'The UPSC CSE 2026 Civil Services Examination notification is expected to be published in February 2026 on upsc.gov.in. The Prelims is likely to be held in May–June 2026. The exam calendar published by UPSC at the beginning of each year gives exact dates.' },
    { question: 'What is the difference between UPSC Prelims and Mains?', answer: 'Prelims: Two objective papers (GS Paper I + CSAT), 200 marks each, 2 hours each, negative marking of 0.66 per wrong answer. Mains: Nine descriptive papers (Essay, GS I–IV, Optional I–II, Language I–II), each 250–300 marks. Only candidates who clear Prelims (cutoff varies 90–98 out of 400) appear for Mains.' },
    { question: 'upsc 2026 notification date', answer: 'The UPSC CSE 2026 Civil Services Examination notification is expected to be published in February 2026 on the official UPSC website (upsc.gov.in). The notification details include: exam dates, eligibility criteria, number of attempts, age limit relaxation rules, examination centres, and the online application link. Candidates should regularly check upsc.gov.in for updates. The notification is typically released in the first week of February each year.' },
    { question: 'upsc 2026 prelims date', answer: 'UPSC CSE 2026 Preliminary Examination is expected to be held in May–June 2026 (typically the last Sunday of May or first Sunday of June). The exact date is announced in the official notification published in February 2026. UPSC Prelims consists of two papers: General Studies Paper I (200 marks) and CSAT Paper II (200 marks, qualifying). Both papers are objective MCQ format with negative marking for wrong answers.' },
    { question: 'upsc 2026 syllabus changed', answer: 'No major syllabus changes have been announced for UPSC CSE 2026. ThePrelims and Mains syllabus remains the same as in previous years. The Prelims syllabus covers current events, history, geography, polity, economy, science & environment, and ethics. The Mains syllabus includes Essay, General Studies I–IV, Optional papers, and language papers. UPSC occasionally makes minor changes to the exam pattern or marking scheme — candidates should check the 2026 notification for any updates.' },  ],
  'pcat': [
    { question: 'What is the PCAT and which Philippine universities accept it?', answer: 'The PCAT (Philippine College Admissions Test) is a standardized entrance examination used by a number of colleges and universities in the Philippines for admission to undergraduate programmes. While not all Philippine universities require the PCAT, many use it as part of their holistic admissions process alongside students\' high school grades and interview performance. The exam tests verbal ability, quantitative skills, reading comprehension, and scientific reasoning. Students should check their target university\'s admission requirements directly as policies vary across institutions.' },
    { question: 'What is the NMAT Philippines and how does it differ from PCAT?', answer: 'The NMAT Philippines (National Medical Admission Test) is specifically for students seeking admission to medical schools in the Philippines — it is NOT the same as the PCAT. NMAT measures academic aptitude for medical studies specifically, covering Physics, Chemistry, Biology, and Mental Ability. PCAT is broader and used for general university admissions. If you are targeting medical school in the Philippines, you need the NMAT, not the PCAT. NMAT scores are also used for merit-based scholarships at some institutions.' },
  ],
  'uAeu_cat': [
    { question: 'What is the UAEU CAT and how does it work?', answer: 'The UAE Universities Common Admission Test (UAEU CAT) is an entrance examination conducted by the United Arab Emirates University (UAEU) for admission to its undergraduate programmes. UAEU is the oldest and most prestigious federal university in the UAE. The exam assesses candidates in English proficiency, mathematics, and reasoning abilities. It is primarily for students who have completed their secondary education (Grade 12) and are seeking admission to UAEU\'s degree programmes in fields including engineering, business, humanities, and science.' },
    { question: 'What is the exam pattern for UAEU CAT?', answer: 'The UAEU CAT typically consists of multiple-choice questions in three sections: English Language (grammar, vocabulary, reading comprehension), Mathematics (algebra, geometry, arithmetic), and Logical Reasoning/Analytical Skills. The exam is conducted online at designated test centres in the UAE. Candidates are given approximately 2–3 hours to complete the test. Some programmes may have additional subject-specific sections. Candidates should check the specific requirements for their intended programme on the UAEU admissions portal.' },
  ],
  'utbk': [
    { question: 'What is UTBK and how does it work?', answer: 'UTBK (Ujian Tulis Berbasis Komputer) is Indonesia\'s national computer-based university entrance exam, conducted by the National Testing Center (Pusat Penilaian Pendidikan) under the SNPMB system. It is mandatory for students seeking admission to most public universities through the SNBT (Seleksi Nasional Berdasarkan Tes) pathway. UTBK consists of the Academic Potential Test (TPA) covering verbal, numerical, and figural reasoning, plus subject-specific tests. The score is valid for one admission cycle only.' },
    { question: 'What is the UTBK exam pattern?', answer: 'UTBK consists of 195 questions to be answered in 195 minutes (3 hours 15 minutes). The test has two components: TPS (Tes Potensi Skolastik) — measuring academic potential through verbal reasoning, quantitative reasoning, and figural reasoning; and subject-specific tests (Matematika, Fisika, Kimia, Biologi, Sosiologi, Ekonomi, Sejarah, and/or Geografi depending on the study programme chosen). All questions are multiple-choice. The exam is computer-based at designated testing centres across Indonesia.' },
    { question: 'How is the UTBK score used for university admission?', answer: 'UTBK scores are used for two pathways: SNBP (Seleksi Nasional Berdasarkan Prestasi) — for high school rank-based admission without needing UTBK; and SNBT — the test-based selection requiring a UTBK score. The minimum score requirement varies by university and programme. Most competitive programmes at top universities (UI, UGM, ITB, IPB) require high UTBK scores (above 650–700 depending on subject combination). The score is combined with other criteria in the final admission decision.' },
  ],
  'qimiyah': [
    { question: 'What is the Qimiyah exam in Saudi Arabia?', answer: 'Qimiyah (قيمة) is a scholarship or admission examination used by Saudi Arabian universities and educational authorities for evaluating students seeking admission to specific programmes, particularly in health sciences and applied fields. The exam is part of Saudi Arabia\'s broader effort to standardise student assessment and scholarship allocation across the Kingdom. The exact format and university acceptance vary by institution. Students applying for merit-based scholarships or competitive programmes in Saudi universities may be required to take the Qimiyah exam as part of their application.' },
  ],
  'cat': [
    { question: 'What is the eligibility to appear for CAT?', answer: 'Candidates must hold a Bachelor\'s degree with at least 50% marks (45% for SC/ST/PwD) from a recognised university. Final-year undergraduate students can also apply. There is no minimum work experience requirement. Candidates from any academic background — engineering, arts, commerce, science — are eligible.' },
    { question: 'What is the CAT exam pattern?', answer: 'CAT is a computer-based test of 2 hours (120 minutes). The exam has three sections: VARC (24 questions), DILR (20 questions), and QA (22 questions). Each correct answer carries 3 marks; 1 mark is deducted for each wrong answer in the MCQ section. There is no negative marking for TITA (Type in the Answer) questions. The test is adaptive in some years.' },
    { question: 'What is a good CAT score for IIM admission?', answer: 'A CAT score above 99 percentile (typically 97–99+ sectional percentiles) is considered competitive for top IIMs (IIM-A, B, C, L, K, S). The exact cutoff varies by IIM, category, and academic background. For newer IIMs and baby IIMs, the 90–95 percentile range is usually sufficient. Beyond the CAT score, WAT and PI rounds also carry significant weight in the final selection.' },
  ],
  'jee-main': [
    { question: 'What is JEE Main and how does it relate to JEE Advanced?', answer: 'JEE Main (Joint Entrance Examination — Main) is India\'s premier engineering entrance exam conducted by NTA (National Testing Agency). It is the first of the two-stage JEE examination system — JEE Main qualifies candidates for JEE Advanced (the exam for admission to IITs). JEE Main is also used for admission to NITs (National Institutes of Technology), IIITs (Indian Institutes of Information Technology), and other government-funded technical institutions. Over 1 million students appear for JEE Main each year across multiple sessions (typically 2–4 sessions per year). The best of multiple sessions is used for the final rank list.' },
    { question: 'What is the JEE Main exam pattern?', answer: 'JEE Main has two papers — Paper 1 (B.E./B.Tech) and Paper 2 (B.Arch/B.Planning). Paper 1 consists of 90 multiple-choice questions (MCQs) across three sections: Physics (30 questions), Chemistry (30 questions), and Mathematics (30 questions). Each correct answer carries 4 marks; 1 mark is deducted for each wrong answer. The exam is conducted online (CBT) for 3 hours. From 2024 onwards, JEE Main has moved to a new pattern with 20 mandatory Numerical Value questions (non-MCQ) per section — these have no negative marking. The exam is held in multiple sessions (usually February, March, April, May) — the best NTA score is considered for the final rank.' },
    { question: 'What JEE Main rank do I need for NITs and top colleges?', answer: 'For admission to top NITs (NIT Trichy, NIT Surathkal, NIT Warangal, NIT Calicut), a JEE Main rank within the top 20,000 is typically required for Computer Science. For other top branches (Electronics, Mechanical) at good NITs, a rank within 10,000–15,000 is needed. For lower-ranked NITs, a rank within 50,000–80,000 may be sufficient. The JEE Main percentile score is used for JoSAA counselling — 50% of seats in NITs are allocated based on JEE Main rank, 40% based on Class 12 board marks, and 10% for diversity (state quota). The Opening and Closing rank for each NIT and branch varies significantly each year based on category and seat availability.' },
  ],
  'jee-adv': [
    { question: 'What is JEE Advanced and how does it differ from JEE Main?', answer: 'JEE Advanced is the second and final stage of India\'s two-stage JEE examination system — the exam for admission to the Indian Institutes of Technology (IITs). Only the top 2,50,000 JEE Main rankers (by percentile) are eligible to appear for JEE Advanced. It is conducted by one of the IITs (rotating annually — IIT Madras in 2025, IIT Kanpur in 2024). JEE Advanced is widely considered one of the toughest undergraduate entrance exams in the world. Approximately 1,10,000 candidates appeared for JEE Advanced in 2024, competing for around 17,000 B.Tech seats across all 23 IITs.' },
    { question: 'What is the JEE Advanced exam pattern?', answer: 'JEE Advanced consists of two papers (Paper 1 and Paper 2), both compulsory, conducted on the same day in online (CBT) mode. Each paper has 3 hours and includes questions from Physics, Chemistry, and Mathematics. The question types include: Multiple Choice Questions (single correct option), Multiple Select Questions (multiple correct options), Numerical Value Questions (integer answers), and Matching Questions. There is a negative marking for some question types. The exam is typically held in May/June each year. Candidates must score above the cutoff in each subject to qualify for counselling.' },
    { question: 'What rank do I need for IIT admission through JEE Advanced?', answer: 'For admission to the top IITs (IIT Bombay, Delhi, Madras, Kanpur, Roorkee), a rank within the top 5,000 is typically required for Computer Science. For other popular branches at top IITs (Electrical, Mechanical at IIT B/D/M), a rank within 10,000 is needed. For newer IITs (IIT Tirupati, IIT Hyderabad, IIT (BSBE)), a rank within 15,000–20,000 may be sufficient. The JEE Advanced rank is used for JoSAA and CSAB counselling. The opening and closing ranks vary significantly by IIT, branch, and category each year. The total marks in JEE Advanced vary each year (not fixed), so the rank matters more than the raw score.' },
  ],
  'ioe-ent': [
    { question: 'What is IOE Entrance and how does Nepal engineering admission work?', answer: 'IOE Entrance (Institute of Engineering Entrance Examination) is Nepal\'s national-level engineering entrance exam, conducted by the Institute of Engineering at Tribhuvan University. It is the gateway for admission to Nepal\'s premier engineering programmes at Pulchowk Campus (the top engineering college in Nepal), Thapathali Campus, and other constituent engineering campuses across Nepal. IOE is highly competitive — over 30,000 students appear each year for approximately 1,500 seats in undergraduate engineering programmes. The exam is conducted annually, typically in June/July. The main programmes offered are B.E. (Bachelor of Engineering) in Civil, Computer, Electrical, Electronics, Mechanical, and other disciplines.' },
    { question: 'What is the IOE Entrance exam pattern?', answer: 'IOE Entrance consists of a single paper with 150 multiple-choice questions to be answered in 3 hours. The distribution is: Mathematics (60 questions), Physics (30 questions), and Chemistry (30 questions). Additionally, there is an English test (30 questions) covering grammar, vocabulary, and reading comprehension. Each correct answer carries 1 mark; there is a negative marking of 0.25 marks per wrong answer. The exam is conducted offline (pen-and-paper) at designated centres in Nepal. The difficulty level is comparable to the Nepal Class 12 Board exam (Science faculty). The questions are based on the NEB (National Examination Board) Class 11-12 curriculum.' },
    { question: 'What rank do I need for IOE admission to top campuses?', answer: 'The IOE merit list is national-level and highly competitive. For admission to Pulchowk Campus (the most prestigious — Civil, Computer, Electrical, Electronics Engineering), a rank within the top 200 is typically required. For Thapathali Campus (Mechanical, Civil, Computer), a rank within the top 1,000 is needed. For other constituent campuses (Paschimanchal, Nepal Engineering College, etc.), a rank within the top 3,000–5,000 is competitive. The IOE counselling process allocates seats based on rank and student preferences across campuses and disciplines. IOE scores are also accepted by some private engineering colleges in Nepal as part of their admission process.' },
  ],
  'cs-exec': [
    { question: 'What is CS Executive and how does it work?', answer: 'CS Executive (Company Secretary Executive) is the second level of the Company Secretary qualification conducted by ICSI (Institute of Company Secretaries of India). The three levels are: Foundation → Executive → Professional. Students who have cleared CS Executive or graduates in any discipline can directly appear for CS Executive. The CS Executive programme covers corporate law, company accounts, tax law, and management accounting. After passing CS Executive, students must complete 15 months of practical training (articleship) before appearing for CS Professional. A Company Secretary is a legal compliance professional for companies — distinct from Chartered Accountants.' },
    { question: 'What is the CS Executive exam pattern?', answer: 'CS Executive has two modules, each with 4 papers (8 papers total): Module 1 — Company Accounts & Auditing Practices, Tax &Labour Laws, Capital Markets & Corporate Laws; Module 2 — Corporate & Management Accounting, Securities Laws & Capital Markets, Economic & Commercial Laws. Exams are held twice a year (June and December). Each paper is of 100 marks (70 marks written + 30 marks practical/case study). Students must score 40% in each paper and 50% aggregate in each module to pass. Negative marking applies (0.25 per wrong answer for objective parts).' },
    { question: 'How should I prepare for CS Executive exams?', answer: 'CS Executive has a low pass rate — typically 5–15% in each paper — making it one of the tougher professional exams. The key is focusing on the Company Accounts and Tax papers, which are the highest-scoring. ICSI study material (both Module-wise and Practice Manuals) is essential. MCQs and case studies carry significant weight, so practice previous year question papers thoroughly. Join a test series 2 months before exams to build speed. Many students take multiple attempts — the exam tests depth of legal knowledge rather than just memory.' },
  ],
  'cma': [
    { question: 'What is CMA and how does it work?', answer: 'CMA (Certified Management Accountant) in India is conducted by ICMAI (Institute of Cost Accountants of India) — formerly known as ICWAI. There are three levels: CMA Foundation → CMA Intermediate → CMA Final. After passing all three levels and completing 3 years of practical experience, you become a Cost and Management Accountant. CMAs work in cost accounting, financial management, management accounting, and corporate finance roles — distinct from Chartered Accountants who focus more on audit and taxation. The CMA qualification is globally recognised (USA\'s IMA also awards CMA) and is valued in manufacturing, banking, and consulting sectors.' },
    { question: 'What is the CMA exam pattern?', answer: 'CMA Intermediate has two groups with 4 papers each: Group 1 — Law & Ethics, Financial Accounting, Direct Taxation, Cost Accounting; Group 2 — Advanced Accounting, Management Accounting, Indirect Taxation, Financial Management. Each paper is 100 marks (70 descriptive + 30 objective). CMA Foundation is objective (100 MCQs per paper, 4 papers). CMA Final has 4 descriptive papers. Exams are held twice a year (June and December). To pass, students need 40% in each paper and 50% aggregate per group. Negative marking applies for the objective portions (0.25 per wrong answer).' },
    { question: 'How does CMA compare to CA and which should I choose?', answer: 'CMA and CA (Chartered Accountant) both lead to finance/accounting careers but differ in focus: CA emphasises auditing, taxation, and compliance; CMA emphasises cost management, financial strategy, and corporate finance. CMA is generally considered slightly easier to qualify than CA (pass rates are higher), and CMAs are in strong demand in manufacturing, FMCG, and consulting firms for cost control and financial analysis roles. If you want to work in audit/taxation, choose CA; if you want corporate finance/cost management, CMA is the better fit. Many professionals hold both qualifications.' },
  ],
  'comedk': [
    { question: 'What is COMED-K and who is it for?', answer: 'COMED-K (Consortium of Medical, Engineering and Dental Colleges of Karnataka) is the entrance exam for admission to undergraduate professional programmes in private colleges across Karnataka. It is specifically for students who have completed their Class 12 (2nd PUC) from any recognised board in India — unlike KCET which is primarily for Karnataka domicile students, COMED-K is open to students from all Indian states. COMED-K covers B.Tech (Engineering), B.Arch, B.Pharm, and other professional courses in approximately 150+ private unaided colleges in Karnataka. It is the largest private engineering admission exam in Karnataka and is conducted annually by the Consortium.' },
    { question: 'What is the COMED-K exam pattern?', answer: 'COMED-K consists of 180 multiple-choice questions to be answered in 3 hours. For B.Tech admission: Physics (60 questions), Chemistry (60 questions), and Mathematics (60 questions). Each correct answer carries 1 mark; there is no negative marking. The exam is conducted offline (pen-and-paper) at designated centres in Karnataka and major cities across India. The difficulty level is moderate — roughly equivalent to the Karnataka Board Class 12 standard. COMED-K also has a separate exam for Medical (NEET-based ranking) and Dental programmes.' },
    { question: 'What rank do I need for COMED-K admission?', answer: 'COMED-K does not release official cutoffs but publishes rank ranges. For top private engineering colleges in Bangalore: a rank within 1,000 is needed for Computer Science at RV College of Engineering (through COMED-K quota), PES University, and BMS College of Engineering. For top colleges in Bangalore and Mysore: rank within 3,000 for CS. For good colleges across Karnataka: rank within 10,000. COMED-K counselling allocates seats in two rounds. The COMED-K management quota is separate from the government merit quota and has higher fees. For NRI candidates, separate seats are available with higher fees. Key advantage over KCET: COMED-K is open to students from all states, making it the best option for non-Karnataka students seeking engineering admission in Karnataka.' },
  ],
  'ca-found': [
    { question: 'What is CA Foundation and how does it work?', answer: 'CA Foundation is the entry-level examination for the Chartered Accountancy profession in India, conducted by ICAI (Institute of Chartered Accountants of India). It is the first of three levels: CA Foundation → CA Intermediate → CA Final. After passing CA Foundation, students enter the CA Intermediate course, then do articleship training, and finally clear CA Final to become a Chartered Accountant. CA Foundation can be attempted by students who have completed Class 12 (or are appearing) from any stream — Commerce, Science, or Arts. Students from Commerce background have a slight advantage as Accounting and Business Laws overlap with Class 11-12 Commerce curriculum.' },
    { question: 'What is the CA Foundation exam pattern?', answer: 'CA Foundation consists of four papers, all conducted in offline pen-and-paper mode: Paper 1 — Principles and Practice of Accounting (100 marks, 3 hours), Paper 2 — Business Laws & Business Correspondence (100 marks, 3 hours, covering Company Law and the Indian Contract Act), Paper 3 — Business Mathematics, Logical Reasoning & Statistics (100 marks, 2 hours), and Paper 4 — Business Economics & Business and Commercial Knowledge (100 marks, 2 hours). Paper 3 allows use of a basic calculator; Paper 4 is objective-type. Students must score 40% in each paper and 50% aggregate to pass.' },
    { question: 'How should I prepare for CA Foundation?', answer: 'CA Foundation has a high pass rate compared to Intermediate and Final — typically 20–30% of candidates pass. The key is focusing on Paper 1 (Accounting) which is the highest-scoring and most scoring-friendly paper for Commerce students. Paper 2 (Business Laws) requires factual memorisation of sections and case law precedents. Papers 3 and 4 require practice. ICAI publishes the complete study material (all four modules) and practice manuals — these are essential. Join a test series in the last 2 months before the exam to build speed and confidence. Most first-attempt clears focus on ICAI material and RTP (Revision Test Papers).' },
  ],
  'mat': [
    { question: 'What is MAT and which B-schools accept it?', answer: 'MAT (Management Aptitude Test) is a national-level MBA entrance exam conducted by AIMA (All India Management Association). It is accepted by over 600 B-schools across India, including many private and semi-government institutions. MAT is conducted in both paper-based test (PBT) and computer-based test (CBT) modes, typically 4 times a year (February, May, September, December). It is particularly useful for candidates targeting tier-2 and tier-3 B-schools where MAT scores are the primary criterion for admission.' },
    { question: 'What is the MAT exam pattern?', answer: 'MAT consists of 4 sections with 200 multiple-choice questions total, to be answered in 150 minutes (2 hours 30 minutes): Language Comprehension (40 questions), Mathematical Skills (40 questions), Data Analysis & Sufficiency (40 questions), and Economic & Business Environment/Intelligence & Critical Reasoning (40 questions, split across two sub-sections). There is negative marking of 0.25 marks per wrong answer. The exam is available in both offline (PBT) and online (CBT) formats in over 50 test cities across India.' },
    { question: 'What is a good MAT score for admission?', answer: 'A MAT score of 500+ out of 800 (approximately 60%) is generally considered competitive for tier-2 B-schools. For top MAT-accepting colleges like BIMTECH (Greater Noida), IISWBM (Kolkata), and PIBM (Pune), a score above 600 is preferred. The MAT percentile is calculated based on the normalised score across all test takers. Unlike CAT, MAT cutoffs are typically set lower — a percentile above 70 (score ~550+) is enough for most MAT-accepting institutions. After shortlisting, most colleges conduct their own GD-PI rounds.' },
    { question: 'How is MAT different from CAT and which should I take?', answer: 'MAT and CAT differ in several key ways: CAT is harder (higher difficulty, adaptive), accepted by top IIMs and premier B-schools; MAT is easier, more predictable, and accepted by 600+ tier-2/3 B-schools. CAT is conducted once a year (November); MAT is conducted 4 times a year, offering flexibility. If your target is a top-tier B-school (IIM-A/B/C, FMS, MDI), take CAT. If you are targeting a good but not top-ranked college and want multiple attempts, take MAT — your MAT score can get you into decent B-schools while you also prepare for CAT. Many candidates take both exams simultaneously.' },
  ],
  'nmat': [
    { question: 'What is NMAT and which B-schools accept it?', answer: 'NMAT (NMIMS Management Aptitude Test) is conducted by GMAC (Graduate Management Admission Council) — the same body that conducts the GMAT — for admission to NMIMS (Narsee Monjee Institute of Management Studies) campuses in Mumbai, Bangalore, Hyderabad, and other NMIMS campuses. It is also accepted by several other B-schools in India including SPJIMR (for their programmes), ISBR, and a few international universities. NMAT is taken by candidates who want a shot at NMIMS specifically without having to compete in CAT. The exam is known for being moderate in difficulty with a predictable structure.' },
    { question: 'What is the NMAT exam pattern?', answer: 'NMAT consists of three sections: Language Skills (36 questions, 28 minutes), Quantitative Skills (36 questions, 52 minutes), and Logical Reasoning (36 questions, 40 minutes) — 108 questions total to be answered in 120 minutes. There is no negative marking in NMAT — a unique feature among major Indian MBA entrance exams. The exam is adaptive within sections (difficulty adjusts based on performance). NMAT can be taken up to 3 times per season (initial attempt + 2 retakes), and the best score is used for admission. The exam is conducted at designated test centres between October and December each year.' },
    { question: 'What score do I need for NMIMS through NMAT?', answer: 'A NMAT score of 220+ out of 360 is generally considered competitive for NMIMS Mumbai (the flagship campus). For NMIMS Bangalore and Hyderabad, 200+ is typically sufficient. The NMAT score is reported as a scaled score (with section-wise and overall scores). Unlike CAT, there is no negative marking — candidates are encouraged to attempt all questions. Since there are 3 attempts available and the best score counts, candidates often take multiple attempts to improve their score. The NMAT percentile is prepared by GMAC based on the normalised scaled scores across all test takers.' },
  ],
  'ipmat': [
    { question: 'What is IPMAT and which IIM offers it?', answer: 'IPMAT (Integrated Programme in Management Aptitude Test) is conducted by IIM Indore for admission to its 5-year Integrated Programme in Management (IPM). This is a unique programme that combines an undergraduate degree (BBA) with an MBA — students spend the first 3 years on the BBA portion at IIM Indore\'s campus, followed by 2 years of MBA. After completing the 5-year programme, graduates receive an MBA degree from IIM Indore. It is one of the most competitive undergraduate management programmes in India — only around 150 seats are available, and over 50,000 students apply each year. After IPMAT Indore, IIM Ranchi also started an IPM programme.' },
    { question: 'What is the IPMAT exam pattern?', answer: 'IPMAT Indore consists of two sections: Quantitative Ability (QA) and Verbal Ability (VA). Both sections have both MCQ and Short Answer (SA) question types. The QA section has 30 MCQs + 10 SA; VA has 30 MCQs + 10 SA. Each MCQ carries 4 marks with -1 for wrong answers; each SA carries 4 marks with no negative marking. Total duration is 2 hours 30 minutes. The exam is conducted online (CBT) at designated centres. There is no General Awareness section — a key difference from IPMAT Ranchi.' },
    { question: 'What score do I need for IIM Indore IPM?', answer: 'A normalised score of 320+ out of 400 is generally competitive for IIM Indore IPM. The sectional cutoffs are typically around 70-80 marks in QA and 70-80 marks in VA. Since only the top 250-300 candidates are called for WAT-PI (Written Ability Test and Personal Interview), a high score in both sections is important. After WAT-PI, the final admission offer is based on: IPMAT score (40%), WAT-PI (30%), Class 10 and 12 marks (15% each).Candidates with strong academic backgrounds and communication skills have an advantage at the WAT-PI stage.' },
  ],
  'mdcat': [
    { question: 'What is the eligibility for MDCAT?', answer: 'Candidates must have completed F.Sc. (Pre-Medical) or an equivalent qualification with a minimum of 65% marks aggregate. They must also appear in the MDCAT entrance test conducted by PMDC. For international seats, the requirements may differ — check with the respective university. The test is mandatory for admission to all medical colleges in Pakistan.' },
    { question: 'What is the exam pattern for MDCAT?', answer: 'MDCAT is a multiple-choice question (MCQ) based test of 180 questions to be attempted in 3 hours and 30 minutes. The distribution is: Biology (60 MCQs), Chemistry (60 MCQs), Physics (30 MCQs), and English (30 MCQs, usually from University Admission Test pattern). The test is conducted annually, typically in August or September. Negative marking applies: 0.5 marks deducted per wrong answer.' },
    { question: 'What is the passing score for MDCAT?', answer: 'The PMDC sets a minimum passing threshold each year. The passing marks are typically 65% overall. For government medical colleges, the merit is calculated based on MDCAT score (50%), F.Sc./HSSC marks (40%), and interview (10%) or as per the latest PMDC policy. Private medical colleges set their own merit thresholds.' },
  ],
  'fpsc-cce': [
    { question: 'What is FPSC-CSS and how does it work?', answer: 'FPSC-CSS (Federal Public Service Commission — Central Superior Services Examination) is Pakistan\'s most prestigious civil service entrance exam, conducted annually by the Federal Public Service Commission. It is the primary pathway for recruitment to Pakistan\'s bureaucratic elite — positions include District Management Group (DMG), Police Service of Pakistan (PSP), Foreign Service of Pakistan, Commerce & Trade Group, and other prestigious occupational groups. CSS officers are appointed as Assistant Commissioners, Deputy Secretaries, and eventually rise to senior positions in the federal government including Secretary-level posts. The exam is open to graduates from any Pakistani university (or equivalent) up to 30 years of age (32 for certain groups).' },
    { question: 'What is the FPSC-CSS exam pattern?', answer: 'FPSC-CSS consists of two stages: Written Examination (compulsory and optional papers) and Viva Voice (interview). Compulsory papers (total 600 marks): English (100 marks), General Science & Ability (100 marks), Current Affairs (100 marks), Pakistan Affairs (100 marks), and Islamic Studies/Pakistan Studies (100 marks). Optional papers (600 marks total): candidates choose 2 papers from a list of 24 groups including: Political Science, International Relations, Economics, Commerce, Sociology, History, Geography, Mathematics, Physics, Chemistry, Botany, Zoology, and others. Each optional paper is 100 marks. The written exam is held in February each year across major cities in Pakistan.' },
    { question: 'What score do I need to pass FPSC-CSS?', answer: 'FPSC sets a minimum qualifying marks each year — typically 50% in each paper and 40% in the aggregate. However, actual cutoffs for final selection are much higher due to competition. In recent years, the final cutoff for recommended candidates has been around 550–600 out of 1200 (competitive marks). The Viva Voce (interview) carries 100 marks and is crucial — it can make or break a candidate\'s final ranking. The most competitive occupational groups by preference are: Foreign Service of Pakistan (requires excellent English and current affairs), DMG (requires high academic scores), and Police Service (身体 and leadership qualities). The FPSC psychological assessment is also part of the selection process for DMG candidates.' },
  ],
  'du-ad': [
    { question: 'What is DU Admission Test (Bangladesh) and how does it work?', answer: 'DU Admission (Bangladesh) refers to the University of Dhaka\'s undergraduate admission test — the most competitive university entrance exam in Bangladesh. Dhaka University admits undergraduates through its own admission test, which is taken after the H.S.C. (Class 12) exam. The test is divided into four units: Unit A (Science background), Unit B (Commerce background), Unit C (Humanities background), and Unit D (Institute of Fine Arts). Each unit has separate eligibility based on H.S.C. subject combination. The DU admission test is highly competitive — only around 5–7% of applicants secure admission. For the most popular departments like Economics, Sociology, and Psychology at DU, a rank within the top 500 is typically required.' },
    { question: 'What is the DU Admission test pattern?', answer: 'The DU admission test consists of written examinations for most units. Unit A (Science): 100 marks written test covering Physics, Chemistry, Mathematics/Biology (based on H.S.C. background), plus a separate English test. Unit B (Commerce): written test on Accounting, Business Organisation, Economics and English. Unit C (Humanities): written test on multiple subjects from Humanities group. Unit D (Fine Arts): practical exam and viva. Each unit test is typically 100 marks. The questions are a mix of multiple-choice (MCQ) and written/descriptive answers. DU also has a merit-based quota system: 60% on admission test, 10% on H.S.C. GPA, 5% on extracurricular activities, and 5% on diversity (district quota).' },
    { question: 'How does DU admission ranking and merit calculation work?', answer: 'DU admission uses a combined merit system: 60% from the admission test score, 10% from H.S.C. Equivalent Point (GPA fromSSC and H.S.C. combined), 5% from extracurricular activities, and the remaining varies by quota category. The total weighted score determines the merit ranking. For admission to top departments like Economics (Unit C) at Dhaka University, a merit position within the top 300 is needed. For popular science departments (Unit A), ranks within top 200 are typically required for Computer Science and Engineering. After the written test, selected candidates go through a viva voce. The final selection is based on combined performance in written test and viva. Approximately 4,500 seats are available across all departments at Dhaka University each year.' },
  ],
  'ecat': [
    { question: 'What is the eligibility for ECAT?', answer: 'Candidates must have completed F.Sc. (Pre-Engineering) or an equivalent qualification with Physics, Chemistry, and Mathematics as compulsory subjects. A minimum of 60% marks in the HSSC or equivalent is typically required. Students appearing in their final HSSC exam are also eligible to appear for ECAT. The test is mandatory for admission to all engineering universities in Punjab, Pakistan.' },
    { question: 'What is the ECAT exam pattern?', answer: 'ECAT is a multiple-choice question (MCQ) test of 100 questions to be attempted in 1 hour and 45 minutes. The distribution is: Chemistry (30 MCQs), Physics (30 MCQs), Mathematics (30 MCQs), and English/General Knowledge (10 MCQs). Each correct answer carries 4 marks; there is no negative marking in ECAT. The test is conducted computer-based (CBT) at designated test centres across Pakistan.' },
    { question: 'How is the ECAT merit calculated?', answer: 'The ECAT merit is calculated as: ECAT Score (50%) + HSSC/F.Sc. Aggregate (40%) + Interview (10%) or as per the latest policy of the respective university. The aggregate percentage is calculated on the basis of marks obtained in Physics, Chemistry, and Mathematics. Universities like UET Lahore, UET Taxila, and other public sector engineering colleges use the ECAT score as the primary criterion for admission to engineering degree programmes.' },
  ],
  'ecat-eng': [
    { question: 'What is ECAT-ENG and how does it differ from ECAT?', answer: 'ECAT-ENG (Engineering) is a variant of the Engineering, Agriculture, and Medical Combined Test specifically for admission to engineering degree programmes in Pakistani universities. While ECAT covers all three streams (Engineering, Agriculture, Medical), ECAT-ENG focuses exclusively on engineering admissions and is accepted by universities that require an engineering-specific test score. In practice, many universities accept either ECAT or ECAT-ENG interchangeably — but ECAT-ENG is preferred by engineering-specific universities and as an additional test score for students targeting multiple engineering colleges.' },
    { question: 'What is the ECAT-ENG exam pattern?', answer: 'ECAT-ENG consists of 100 multiple-choice questions to be answered in 1 hour and 45 minutes. The distribution is: Mathematics (30 MCQs, worth 120 marks), Physics (30 MCQs, worth 120 marks), Chemistry (30 MCQs, worth 120 marks), and English/General Knowledge (10 MCQs, worth 40 marks). Each correct answer carries 4 marks. There is no negative marking in ECAT-ENG. The test is conducted computer-based (CBT) at designated test centres across Pakistan. Questions are based on the F.Sc. (Part 1 and Part 2) syllabus for Mathematics, Physics, and Chemistry.' },
    { question: 'How do I prepare for ECAT-ENG?', answer: 'ECAT-ENG preparation requires strong conceptual understanding of Physics, Chemistry, and especially Mathematics at the F.Sc. level. Focus on NCERT/Textbook exercises for all three subjects — approximately 70% of the questions come directly from textbook concepts. Practice previous year ECAT/ECAT-ENG papers to familiarise yourself with the question pattern and difficulty level. Since there is no negative marking, attempt all questions — even uncertain ones carry a 25% chance of being correct. Join a test series in the last 2 months before the exam to build speed and accuracy. For Mathematics, focus on Calculus, Algebra, and Trigonometry — these carry the highest weight.' },
  ],
  'nat-i': [
    { question: 'What is NAT-I and how does it work?', answer: 'NAT-I (National Aptitude Test – I) is conducted by NTS (National Testing Service) Pakistan for admission to undergraduate programmes in Pakistani universities. It is a multiple-choice question (MCQ) test assessing Verbal Reasoning, Analytical Reasoning, Quantitative Reasoning, and Subject Knowledge. Unlike ECAT which is university-specific, NAT-I is accepted by multiple universities across Pakistan as part of their admission criteria.' },
    { question: 'What is the NAT-I exam pattern?', answer: 'NAT-I consists of approximately 90 MCQs to be answered in 2 hours (120 minutes). The test covers four areas: English (20 MCQs, vocabulary, grammar, reading comprehension), Analytical Reasoning (20 MCQs), Quantitative Reasoning (20 MCQs), and a Subject section (30 MCQs based on the candidate\'s F.Sc. or intermediate stream). There is no negative marking in NAT-I. The test is conducted paper-based at designated NTS test centres.' },
    { question: 'How is NAT-I used in university admissions?', answer: 'NAT-I scores are submitted directly to universities during the application process. Each university sets its own minimum NAT-I score cutoff for different programmes. For competitive programmes like engineering or medicine, a NAT-I score above 70 out of 100 is typically expected. Some universities use NAT-I combined with F.Sc. marks to calculate a merit aggregate — a higher NAT-I score can significantly improve your admission chances, especially for scholarship quotas.' },
  ],
  'kuccps': [
    { question: 'What is KUCCPS and how does university admission work in Kenya?', answer: 'KUCCPS (Kenya Universities and Colleges Central Placement Service) is the government body responsible for placing students into Kenyan universities and TVET institutions after the KCSE (Kenya Certificate of Secondary Education) exam. Unlike countries where you take a separate entrance exam, Kenyan university admission is based primarily on your KCSE grade — students apply to KUCCPS after receiving their KCSE results, and KUCCPS places them based on their grades, chosen programmes, and available capacity. KUCCPS handles placement for all public universities in Kenya including the University of Nairobi, Kenyatta University, Egerton University, and others.' },
    { question: 'How is the KUCCPS placement score calculated?', answer: 'KUCCPS calculates placement using the Mean Points Score (MPS) from KCSE results. The KCSE is graded on a scale of 12 points (A to D-). The aggregate cluster points are calculated based on the required subjects for your chosen programme — for example, Engineering programmes require the STEM cluster (Mathematics, Physics, Chemistry, and either Geography or Computer Studies). Each programme at each university has a cutoff cluster points requirement. Students with a mean points score above the cutoff for their programme are eligible for placement. The higher your KCSE grade, the more placement options available.' },
    { question: 'What are the alternatives if I don\'t get placed by KUCCPS?', answer: 'If you don\'t get placed by KUCCPS to your preferred university or programme, you have several options: (1) Join a TVET (Technical and Vocational Education and Training) institution — KUCCPS also places students into TVET courses, which can lead to diploma or certificate programmes; (2) Apply directly to private universities — private universities like United States International University Africa (USIU-Africa), Strathmore University, and others have their own application processes and do not use KUCCPS; (3) Wait for the second round of placement when additional slots may open; (4) Consider improving your KCSE score by retaking the exam the following year. Remember that KUCCPS placement is free — avoid intermediaries who charge for placement services.' },
  ],
  'lat': [
    { question: 'What is LAT and why is it required for law admissions?', answer: 'LAT (Law Admission Test) is a standardised entrance exam required for admission to LLB (Bachelor of Law) programmes at universities in Pakistan — particularly for Punjab University and other major law schools. It tests analytical reasoning, legal aptitude, English comprehension, and general knowledge. A valid LAT score is a mandatory requirement before applying to most Pakistani universities for a 5-year LLB programme.' },
    { question: 'What is the LAT exam pattern?', answer: 'LAT consists of five sections with 100 MCQs total, to be attempted in 2 hours: English (vocabulary, grammar, reading comprehension, 25 MCQs), Analytical Reasoning (25 MCQs), Legal Aptitude (25 MCQs), Pakistan Studies & Islamic Studies (15 MCQs), and General Knowledge/Current Affairs (10 MCQs). There is no negative marking. The passing score is typically 50% for general candidates, though individual universities may set higher thresholds.' },
  ],
  'neco': [
    { question: 'What is NECO and how does it compare to WAEC?', answer: 'NECO (National Examinations Council) is a Nigerian secondary school examination body, similar to WAEC, conducting the Senior Secondary Certificate Examination (SSCE). While WAEC is widely accepted across West Africa, NECO is primarily accepted within Nigeria for university admissions and by Nigerian employers. Like WAEC, NECO requires a minimum of five credit passes including English and Mathematics for most higher education pathways. Many students take both WAEC and NECO to maximise their exam sittings and improve admission chances.' },
    { question: 'What is the NECO exam pattern?', answer: 'NECO SSCE consists of three papers per subject: Paper 1 (Objective, 50 multiple-choice questions), Paper 2 (Essay/Theory), and Paper 3 (Practical for science subjects and some creative subjects). Exams typically run over 3–4 weeks in June/July (first series) and November/December (second series). Results are graded A1–F6, with A1 (75–100%) being the highest. The November/December series is the more commonly taken NECO exam for students finishing secondary school.' },
    { question: 'How do NECO results work with JAMB admissions?', answer: 'For JAMB admission, candidates must have at least five credit passes in NECO (or WAEC) — including English and Mathematics — in not more than two sittings. After passing JAMB\'s UTME, your NECO results are part of the calculation for your admission aggregate score. NECO results are typically released within 2–3 months of the exam. Students who did not meet university cutoffs can re-sit NECO while also improving their JAMB score.' },
  ],
  'nabteb': [
    { question: 'What is NABTEB and how is it different from WAEC/NECO?', answer: 'NABTEB (National Business and Technical Examinations Board) conducts trade and technical examinations for students in Nigerian technical colleges and secondary schools offering vocational subjects. While WAEC and NECO are general academic exams, NABTEB focuses on Business and Technical subjects — including Engineering, Information Technology, Home Economics, and Agriculture. NABTEB certificates are particularly valued for technician-level programmes, polytechnic admissions, and trade-related careers.' },
    { question: 'What is the NABTEB exam pattern?', answer: 'NABTEB exams are structured differently from WAEC: they include both written theory and practical components. For technical subjects (e.g., Electronics, Woodwork, Metalwork), there is a practical paper tested before the written exam. Each subject has a maximum mark based on a combination of objective, theory, and practical components. NABTEB results are graded: Distinction (A1), Credit (B2/B3), Merit (C4/C5/C6), Pass (D7/E8), and Fail (F9). Results are released within 2–3 months of the examination period.' },
    { question: 'Can NABTEB results be used for university admission?', answer: 'NABTEB results can be used for admission to Nigerian polytechnics and monotechnics, but most federal universities primarily accept WAEC and NECO for undergraduate admission. However, some universities accept NABTEB credits for specific technical courses, particularly in Engineering and Applied Sciences. For university-bound students, it is advisable to combine NABTEB vocational subjects with WAEC/NECO academic subjects to broaden both technical and university admission pathways.' },
  ],
  'ncee': [
    { question: 'What is NCEE and who is it for?', answer: 'NCEE (Nigeria Common Entrance Examination) is a standardised selection test conducted for students in Junior Secondary School 3 (JSS3) who wish to gain admission into Federal Government colleges (Unity Colleges) in Nigeria. It is the primary gateway for students to enter Nigeria\'s prestigious Federal Unity Colleges — including Federal Government College Ikom, Enugu, Benin, and 104 other Unity Colleges across the country. Candidates must be in JSS3 or have completed it, typically aged 12–15. The exam is conducted simultaneously across all Unity Colleges in Nigeria each year, typically in January or February.' },
    { question: 'What is the NCEE exam pattern?', answer: 'NCEE consists of three papers: Paper 1 — Mathematics (60 questions, 1 hour), Paper 2 — English Studies (60 questions, 1 hour), and Paper 3 — General Paper (60 questions, 1 hour, covering Quantitative Reasoning, Verbal Reasoning, and Social Studies/Science/Creative Arts). All questions are multiple-choice (objective). There is no negative marking. The exam is conducted on the same day across all test centres. Candidates mark answers on a machine-readable answer sheet.' },
    { question: 'How are NCEE results used for Federal Unity College admission?', answer: 'NCEE scores are used by the Federal Ministry of Education to rank and allocate candidates to Unity Colleges. Each college has a quota for each state. Students from the same state as the college are given priority. After the exam, candidates indicate their college preferences and placement is done centrally based on score and preference. A score above 180 out of 200 is generally considered competitive. Candidates not placed in their preferred college may be allocated to another with available space. The exam is highly competitive — Unity Colleges are among the most sought-after secondary schools in Nigeria.' },
  ],
  'ican': [
    { question: 'What is ICAN and how does it work?', answer: 'ICAN (Institute of Chartered Accountants of Nigeria) is the professional body for chartered accountants in Nigeria. It awards the ACA (Associate Chartered Accountant) qualification, which is recognised across Nigeria and internationally. To become a Chartered Accountant through ICAN, candidates must pass the ICAN examinations (Foundation, Intermediate, and Final levels), complete 3 years of practical training (articleship at an approved firm), and meet the membership requirements. ICAN exams are conducted twice a year (May and November). The qualification is highly regarded in Nigeria\'s banking, finance, oil & gas, and consulting sectors.' },
    { question: 'What is the ICAN exam structure?', answer: 'ICAN has three levels: (1) Foundation — 4 papers covering Accounting, Business Law & Communication, Economics & Finance, and Management & Information Systems. Graduates of recognised universities can attempt directly without the Foundation. (2) Intermediate — 5 papers covering Assurance, Financial Accounting, Management Information Systems, Taxation, and Corporate Financial Management. (3) Final — 5 papers covering Advanced Taxation, Advanced Financial Reporting, Management, Strategy & Control, Case Study, and Advanced Audit & Assurance. All papers are descriptive (not MCQ), held over 3 days each session. Each paper is marked out of 100.' },
    { question: 'How does ICAN compare to ACCA and which should I choose?', answer: 'ICAN and ACCA both lead to chartered accounting careers but differ in geography and focus: ICAN is Nigeria-focused with Nigerian accounting standards (FRS/SAS), tax law (CITA/FIRS), and Companies Act; ACCA is global with International Financial Reporting Standards (IFRS) and UK tax law. ICAN is better if you want to work primarily in Nigeria (Nigerian employers prefer ICAN for local roles). ACCA is better if you want to work internationally or in multinational firms. Many Nigerian accountants hold both qualifications. ACCA also grants exemptions for ICAN Foundation papers. ICAN membership costs approximately ₦50,000–100,000 per attempt depending on the level.' },
  ],
  'ijmb': [
    { question: 'What is IJMB and how does it work?', answer: 'IJMB (Interim Joint Matriculation Board) is a standardised examination body in Nigeria that offers an alternative pathway to university admission. IJMB allows students who did not score the required marks in JAMB to gain direct university admission through the IJMB route. IJMB students study 3 subjects relevant to their intended university course at an accredited IJMB centre for one academic year. After passing the IJMB examination (with the required grade), students can apply for direct entry (200-level) admission into Nigerian universities — bypassing the first year (100-level). IJMB is recognised by all Nigerian universities as an alternative to JAMB for degree programme entry.' },
    { question: 'What is the IJMB exam pattern?', answer: 'IJMB examinations are conducted annually (typically in June–August) at accredited centres across Nigeria. Each student registers for 3 subjects relevant to their intended university programme — for example: Science students take Physics, Chemistry, Biology; Commercial students take Economics, Accounting, Commerce; Arts students take Literature, History, Government. Each subject has 2–3 papers (depending on the subject). Grading is A–F: Grade A (70–100%), Grade B (60–69%), Grade C (50–59%), Grade D (40–49%), Grade E (30–39%), Grade F (0–29%). To qualify for university admission, students typically need a minimum of Grade C (50%) in all 3 subjects.' },
    { question: 'How does IJMB compare to JAMB and which should I choose?', answer: 'JAMB (UTME) is the primary and more common route to Nigerian universities — taken after Secondary School (WASSCE). IJMB is an alternative for candidates who did not score high enough in JAMB or want direct entry (200-level) admission. IJMB advantages: bypass 100-level, shorter degree duration (3 years instead of 4), focus on fewer subjects intensively. JAMB advantages: wider university acceptance, no centre-based study required, lower cost. If you score well in JAMB — take JAMB (100-level entry). If you did not score high enough in JAMB, IJMB is an excellent alternative to still gain university admission in the same year. Many university students who took IJMB report a smoother transition to university because they already studied 3 relevant subjects intensively.' },
  ],
  'hat-ug': [
    { question: 'What is HAT-UG and how is it used?', answer: 'HAT-UG (HEC Admission Test – Undergraduate) is conducted by the Higher Education Commission of Pakistan for admission to undergraduate programmes at HEC-recognised universities. It assesses a candidate\'s readiness for university-level study through four sections: English, Analytical Reasoning, Quantitative Reasoning, and Subject Knowledge. It is accepted by most Pakistani universities as an alternative to individual university entrance exams.' },
    { question: 'What is the HAT-UG exam pattern?', answer: 'HAT-UG consists of approximately 100 MCQs divided across four sections: English (25 MCQs, grammar and reading comprehension), Analytical Reasoning (25 MCQs), Quantitative Reasoning (25 MCQs), and Subject Knowledge (25 MCQs related to the candidate\'s intermediate stream — Science, Commerce, or Arts). The total duration is 2 hours and 30 minutes. There is no negative marking in HAT-UG. The test is conducted online (CBT) at designated centres across Pakistan.' },
  ],
  'jamb': [
    { question: 'What is the eligibility for JAMB?', answer: 'Candidates must have a Senior Secondary School Certificate (SSCE) or its equivalent with at least five (5) credit passes, including English Language and Mathematics (for most courses). The UTME (Unified Tertiary Matriculation Examination) is open to students who have completed or are in their final year of secondary school education. There is no age limit.' },
    { question: 'What is the JAMB UTME exam pattern?', answer: 'JAMB UTME consists of 180 multiple-choice questions to be answered in 2 hours. The four subjects are: Use of English (compulsory for all candidates), and three other subjects relevant to the candidate\'s chosen university course. Each subject has 60 questions. There is no negative marking. The exam is computer-based (CBT).' },
    { question: 'What is the JAMB syllabus and how should I use it?', answer: 'The JAMB syllabus covers all subjects and specifies the topics and objectives for each. Candidates are advised to study the official JAMB syllabus (available on the JAMB website) and focus on the stated objectives under each topic. Past questions from previous years are also highly valuable for pattern recognition and time management practice.' },
  ],
  'waec': [
    { question: 'What is WAEC and why does it matter?', answer: 'WAEC (West African Examinations Council) conducts the WASSCE (West African Senior School Certificate Examination) — the main secondary school leaving exam for students in Nigeria, Ghana, Sierra Leone, Liberia, and The Gambia. A minimum of five credit passes in WASSCE makes you eligible for university admission in Nigeria and other West African countries. WAEC results are also used by employers as proof of secondary school completion across the region.' },
    { question: 'What is the WAEC exam pattern?', answer: 'WAEC WASSCE consists of both written and practical papers. For most academic subjects, there are three components: Paper 1 (Objective, multiple-choice, 50 questions), Paper 2 (Essays/Theory, structured questions), and Paper 3 (Practical for science subjects). Each paper is marked out of 100. Results are graded A1–F, with A1 (75–100%) being the highest and F (0–39%) being a fail. English Language and Mathematics are compulsory for most university admissions.' },
    { question: 'How are WAEC results used for university admission in Nigeria?', answer: 'In Nigeria, JAMB uses WAEC (or NECO) results as part of the admission requirements — candidates must have at least five credit passes in relevant subjects, including English and Mathematics, in not more than two sittings. Some universities require all five credits in a single sitting. After meeting JAMB\'s UTME requirement, your WAEC results are used to calculate your aggregate score for admission. A strong WAEC result significantly improves your chances of gaining admission to competitive courses like Medicine, Engineering, or Law.' },
  ],
  'clat': [
    { question: 'What is the eligibility for CLAT?', answer: 'For the undergraduate CLAT programme, candidates must have completed their Higher Secondary School Certificate (12th grade) or equivalent examination with at least 45% marks (40% for SC/ST/PwD candidates). There is no upper age limit for appearing in CLAT. Candidates appearing in the 12th grade in the current academic year are also eligible to apply.' },
    { question: 'What is the CLAT exam pattern?', answer: 'CLAT (Undergraduate) consists of 150 multiple-choice questions to be answered in 2 hours. The sections are: English Language, Current Affairs (including General Knowledge), Legal Reasoning, Logical Reasoning, and Quantitative Techniques (Mathematics). Each question carries 1 mark; 0.25 marks are deducted for each wrong answer.' },
    { question: 'What is a good CLAT score for top law schools?', answer: 'A score above 100–110 out of 150 is typically competitive for the top 5 NLUs (National Law Universities). For NLU Delhi and the top-tier NLUs, a score of 120+ is considered strong. Since the exam is standardised, the percentile matters more than the raw score. Candidates aiming for NLU-A should target a rank within the top 500.' },
  ],
  'cuet': [
    { question: 'What is CUET and which universities accept it?', answer: 'CUET (Common University Entrance Test) is India\'s national-level entrance exam for undergraduate admission to central universities (like Delhi University, Banaras Hindu University, Jamia Millia Islamia), state universities, and private universities across India. Conducted by NTA (National Testing Agency), it is the single standardised gateway for admission to 200+ universities. CUET replaced the individual university entrances for most central universities from 2022 onwards. It is particularly important for students seeking admission to DU (Delhi University) where CUET scores are the primary criteria for most undergraduate programmes.' },
    { question: 'What is the CUET exam pattern?', answer: 'CUET consists of three parts: Part A — Language Test (25 questions each for two languages chosen by the candidate, out of 13 available languages including English, Hindi, Tamil, Telugu, etc.). Part B — Domain-specific subjects (25 questions per domain, chosen based on the programme applied for — e.g., Physics, Chemistry, Mathematics, History, Economics, etc.). Part C — General Test (25 questions covering General Knowledge, Current Affairs, Mental Ability, and Quantitative Reasoning). Candidates attempt one Language + up to 3 Domain subjects + General Test. Each question is an MCQ with 4 options; 5 marks per correct answer, -1 for wrong answer. The exam is conducted online (CBT) in multiple sessions across India.' },
    { question: 'How are CUET scores used for Delhi University admission?', answer: 'DU (Delhi University) uses CUET scores as the primary criteria for admission to most undergraduate programmes through CSAS (Common Seat Allocation System). CUET scores are normalised across different test sessions using percentile methodology. For top colleges (St. Stephen\'s, Hindu College, SRCC), a CUET score of 650+ out of 800 is typically needed for popular programmes like Economics (Hons) and Political Science. For less competitive programmes, a score of 500–600 is sufficient. Class 12 board marks are not the primary criteria for DU admissions anymore — CUET dominates the selection process. For B.Com (Hons) at top colleges, expect 700+; for B.A. Programme at less competitive colleges, 500+ may suffice.' },
  ],
  'cucet-pg': [
    { question: 'What is CUET-PG and which universities accept it?', answer: 'CUET-PG (Common University Entrance Test — Postgraduate) is NTA\'s national-level entrance exam for admission to postgraduate programmes (MA, MSc, MCom, MBA, LLM, etc.) in central universities and other participating institutions across India. It covers over 90 universities including Delhi University (PG courses), Banaras Hindu University (PG courses), University of Allahabad, and many state universities. CUET-PG replaced individual university entrances for most central universities from 2023 onwards. The exam covers a wide range of disciplines — candidates choose one domain/paper based on their postgraduate programme. It is a single standardised gateway replacing dozens of individual university PG entrances.' },
    { question: 'What is the CUET-PG exam pattern?', answer: 'CUET-PG consists of a single domain-specific paper of 100 multiple-choice questions to be answered in 2 hours (120 minutes). Each question carries 4 marks; 1 mark is deducted for each wrong answer. The exam is conducted online (CBT) in multiple sessions across India. There are over 80 domain-specific papers covering: Humanities (History, Political Science, Sociology, Economics, Psychology, etc.), Sciences (Physics, Chemistry, Mathematics, Botany, Zoology, etc.), Commerce & Management (Accounting, Business Management, Economics), Law (LLM), and others. Candidates select the paper code matching their desired postgraduate programme. The exam is available in English and Hindi (and other regional languages for language papers).' },
    { question: 'What score do I need for CUET-PG admission?', answer: 'CUET-PG scores are reported as percentiles. The cutoffs vary significantly by university and programme. For top central universities like DU, BHU, and University of Allahabad: a percentile above 85–90 (approximately 200+ out of 400) is needed for popular programmes like MBA, Economics (Hons), and Psychology. For less competitive programmes like Arts and Humanities, 70–80 percentile may suffice. CUET-PG is a relatively new exam — cutoffs are still being established. Since multiple universities use CUET-PG, candidates can apply to several universities with a single score through the centralized admission portal. The exam is typically held in June–July each year.' },
  ],
  'cmat': [
    { question: 'What is CMAT and which MBA colleges accept it?', answer: 'CMAT (Common Management Admission Test) is India\'s national-level entrance exam for admission to MBA/PGDM programmes in AICTE-approved management institutes across India. It is conducted by the National Testing Agency (NTA). Unlike CAT (which is primarily for IIMs), CMAT is accepted by over 1,000 AICTE-approved B-schools including SIMB (Symbiosis), MET (Manipal), JAIIB, and many state-supported institutions. It is typically held once a year (January/February) and is a more accessible alternative to CAT for students targeting tier-2 and tier-3 B-schools.' },
    { question: 'What is the CMAT exam pattern?', answer: 'CMAT consists of 4 sections with 100 questions total to be answered in 3 hours (180 minutes): Quantitative Techniques & Data Interpretation (25 questions), Logical Reasoning (25 questions), Language Comprehension (25 questions), and General Awareness (25 questions). Each correct answer carries 4 marks; 1 mark is deducted for each wrong answer. There is no individual sectional time limit — candidates can switch between sections freely. The exam is conducted online (CBT) at designated centres across India. Since 2021, CMAT score is also accepted by some universities for M.Sc. and M.Tech programmes.' },
    { question: 'What is a good CMAT score and which colleges can I get into?', answer: 'A CMAT score of 250+ out of 300 is generally considered excellent and can get you into top CMAT-accepting B-schools. The percentile mapping: 250+ is 95–99+ percentile, 200–250 is 80–95 percentile, and 150–200 is 60–80 percentile. Top B-schools accepting CMAT include: SIMSREE Mumbai (requires 98+ percentile), MET Mumbai (95+ percentile), PUMBA Pune (90+ percentile), and many others. Unlike CAT where the top 1% gets IIM calls, CMAT top scorers get calls from 50+ good B-schools. Since CMAT is a simpler exam than CAT, diligent preparation can yield high scores.' },
  ],
  'llb-ent': [
    { question: 'What is LLB-ENT and what options exist for law admission?', answer: 'LLB-ENT refers to the various law entrance examinations used for admission to 3-year LLB programmes in India (after graduation) and 5-year integrated BA LLB/BCom LLB programmes (after Class 12). The main national exam is CLAT (for NLUs). However, several states conduct their own law entrances: LSAT India (private law schools), AILET (NLU Delhi), AMU Law Test (Aligarh Muslim University), BHU UET (Banaras Hindu University), and DU-LLB (Delhi University Faculty of Law). Each exam has a different pattern and cutoff. After the 3-year LLB (post-graduation), candidates can also appear for LLM admissions through CLAT-PG.' },
    { question: 'What is the 3-year LLB vs 5-year integrated LLB?', answer: '3-year LLB: Taken after graduation (any bachelor\'s degree with 45–50% marks). This is the most common path for working professionals or graduates who did not take a law entrance exam in Class 12. Top 3-year LLB colleges include Faculty of Law (DU), Jamia Millia Islamia, and state law universities. 5-year integrated LLB: Taken immediately after Class 12 — combines graduation with law (BA LLB, BCom LLB, BSc LLB). This saves one year compared to doing graduation then 3-year LLB separately. Top integrated programmes include NLSIU Bangalore (CLAT), NALSAR Hyderabad (CLAT), and WB National University of Juridical Sciences (CLAT). The integrated path is preferred by Class 12 students.' },
    { question: 'How do I choose between CLAT, LSAT India, and state law entrances?', answer: 'If targeting NLUs — take CLAT (only exam for NLU admissions). If targeting private law schools — LSAT India is accepted by 80+ private colleges including Jindal. If targeting Delhi University\'s 3-year LLB — appear for DU-LLAT (Delhi University LLB Entrance Test). For Aligarh Muslim University — take AMU Law Test. For Banaras Hindu University — take BHU UET Law. For state-level government law colleges — check the specific state exam. Many candidates take CLAT + LSAT simultaneously to maximise options. CLAT opens the most doors nationally; LSAT is a good backup for private colleges; state exams are essential for state-level placements.' },
  ],
  'ailet': [
    { question: 'What is AILLET and how does it differ from CLAT?', answer: 'AILLET (All India Law Entrance Test) is conducted by the National Law University (NLU) Delhi for admission to its BA LLB (Hons.) programme. Unlike CLAT (which is a national-level exam for all NLUs and many private law colleges), AILLET is NLU Delhi\'s own entrance exam and is used exclusively for NLU Delhi\'s intake. Since NLU Delhi is consistently ranked among the top 3 law schools in India (alongside NLSIU Bangalore and NALSAR Hyderabad), AILLET is one of the most competitive law entrance exams in India. The exam tests legal aptitude, reasoning, English, and GK — with a strong emphasis on legal reasoning and current affairs.' },
    { question: 'What is the AILLET exam pattern?', answer: 'AILLET consists of approximately 150 multiple-choice questions to be answered in 2 hours. The sections are: English Comprehension (40 questions, reading comprehension, grammar, vocabulary), General Knowledge & Current Affairs (50 questions, covering national/international news, static GK, legal awareness), Legal Aptitude & Reasoning (30 questions, legal propositions, logical deductions), and Elementary Mathematics/Logical Reasoning (30 questions). There is negative marking of 0.25 marks per wrong answer. The exam is conducted offline (pen-and-paper).' },
    { question: 'What is a good AILLET score for NLU Delhi?', answer: 'A score above 125–130 out of 150 is generally considered competitive for NLU Delhi admission. The cutoff for the general category typically ranges between 115–125 depending on the year and number of applicants. Since NLU Delhi admits only 80 students per year through AILLET, it is highly competitive — candidates targeting NLU Delhi should aim for the top 200 ranks. Unlike CLAT, AILLET does not use a centralised counselling process — admission is based solely on the AILLET score and seat allocation done directly by NLU Delhi.' },
  ],
  'al-exam': [
    { question: 'What is the Sri Lanka A/L Examination and who is it for?', answer: 'The Sri Lanka GCE Advanced Level (A/L) Examination is conducted by the Department of Examinations, Sri Lanka, for students who have completed their secondary education (O/L). It is the primary university entrance examination in Sri Lanka — equivalent to A-Levels or the Indian Class 12 board exams. Students choose one of three streams: Science, Commerce, or Arts — and appear for the A/L in their chosen stream. The A/L result (grades A–E) is the key determinant for university admission in Sri Lanka, where admission to public universities is highly competitive and placement is managed through the University Grants Commission (UGC) system.' },
    { question: 'What are the Sri Lanka A/L streams and how do they work?', answer: 'Sri Lanka A/L has three streams: (1) Science Stream — subjects include Physics, Chemistry, Biology, Combined Mathematics, and ICT; (2) Commerce Stream — subjects include Economics, Business Studies, Accounting, and Information Technology; (3) Arts Stream — subjects include Sri Lankan History, Buddhism, Christianity/Islam/Hinduism, Geography, Political Science, and Logic. Students study 3 main subjects (each with theory + practical papers) plus a Common General Test (CGT) covering general knowledge and quantitative skills. Grades are awarded A (Distinction) through E (Fail) for each subject.' },
    { question: 'How are Sri Lanka A/L results used for university admission?', answer: 'Sri Lanka A/L results are processed through the Z-score system — a normalised score that accounts for the difficulty of the exam and the school/section where the student studied. The Z-score determines the merit rank for university admission to public universities. The top Z-scores across all three streams compete for limited seats in popular courses like Medicine, Engineering, and Law. University admission is handled by the UGC Sri Lanka — students submit preferences after A/L results are released (typically in August). The Z-score, stream, and subject combination determine which course a student gets into — arts stream students compete for arts/humanities seats; science stream for STEM seats.' },
  ],
  'lsat': [
    { question: 'What is LSAT India and which law schools accept it?', answer: 'LSAT India is the Indian variant of the Law School Admission Test (LSAT), a globally recognised standardised test for law school admissions. It is conducted by the Law School Admission Council (LSAC) and is accepted by over 80 law schools in India, including Jindal Global Law School (Sonipat), ICOM Law School (Hyderabad), and several other premier private law colleges. LSAT India tests reading comprehension, analytical reasoning, and logical reasoning — skills considered essential for success in law school. It is not mandatory for NLU admissions — those use CLAT — but it is widely accepted by private and deemed law universities.' },
    { question: 'What is the LSAT India exam pattern?', answer: 'LSAT India consists of four sections of multiple-choice questions, each with approximately 22–24 questions, to be completed in 35 minutes per section: Reading Comprehension, Analytical Reasoning (logic games), Logical Reasoning I, and Logical Reasoning II. There is no negative marking in LSAT India. The total test duration is 2 hours and 20 minutes. The exam is conducted online (CBT) at designated test centres. LSAT India scores are reported on a scale of 420–780, with the median score around 580.' },
    { question: 'How does LSAT India scoring work for admissions?', answer: 'LSAT India scores are used by law schools for their own admission processes — there is no centralised counselling like CLAT. Each law school sets its own cutoff score for admission. For top LSAT-India accepting colleges like Jindal Global Law School, a score above 650 is generally competitive. Unlike CLAT, LSAT India does not have a fixed seat allocation process — you apply directly to each law school with your LSAT score. Many candidates use LSAT as a backup alongside CLAT since the skills tested are similar (legal reasoning, reading, logic).' },
  ],
  'ini-cet': [
    { question: 'What is INI-CET and how does it compare to NEET PG?', answer: 'INI-CET (Institute of National Importance Combined Entrance Test) is the entrance exam for postgraduate medical programmes (MD/MS/MCh/DM) at India\'s top autonomous institutions: AIIMS New Delhi, PGIMER Chandigarh, JIPMER Puducherry, NIMHANS Bengaluru, SCTIMST Trivandrum, and RML Institute of Medical Sciences. Unlike NEET-PG (which covers all medical colleges), INI-CET is specifically for the premier A-category institutions. It is conducted twice a year (January and July sessions) by AIIMS New Delhi on behalf of all participating institutes. The July session is the larger one with more seat intake.' },
    { question: 'What is the INI-CET exam pattern?', answer: 'INI-CET consists of a single paper of 300 multiple-choice questions to be answered in 3 hours. The questions cover all subjects from the MBBS curriculum: Pre-clinical (Anatomy, Physiology, Biochemistry), Para-clinical (Pathology, Pharmacology, Microbiology, Forensic Medicine, Community Medicine), and Clinical (Medicine, Surgery, Obstetrics & Gynecology, Pediatrics, and all clinical sub-specialties). Each correct answer carries 1 mark; 0.33 marks are deducted for each wrong answer. The exam is conducted online (CBT) at designated centres across India.' },
    { question: 'What is a good INI-CET score for top institutions?', answer: 'A rank within the top 1,000 is generally competitive for MD/MS courses at the premier AIIMS, PGIMER, and JIPMER. For the July session, a score above 150 out of 300 (50%) is the qualifying cutoff — but actual admission cutoffs are much higher. For AIIMS New Delhi, a rank under 200 is typically needed for popular branches like General Medicine, Radiology, and Orthopedics. The INI-CET merit is used for a centralised counselling process (AIQ seats) across all participating institutions.' },
  ],
  'jipmer': [
    { question: 'What is JIPMER and how does it work?', answer: 'JIPMER (Jawaharlal Institute of Postgraduate Medical Education and Research) is an autonomous medical institution in Puducherry, consistently ranked among the top 3 medical colleges in India alongside AIIMS Delhi and VMMC. JIPMER offers MBBS, MD, MS, and super-speciality programmes. For MBBS, JIPMER used to conduct its own entrance exam (JIPMER MBBS) before the NMC made NEET mandatory for all medical colleges in 2020. Today, JIPMER MBBS admission is through NEET — but JIPMER PG admissions (MD/MS) still use INI-CET. JIPMER\'s Puducherry campus is renowned for its clinical exposure and research opportunities.' },
    { question: 'What is the JIPMER PG exam pattern for MD/MS?', answer: 'JIPMER PG (MD/MS) admission is through INI-CET (Institute of National Importance Combined Entrance Test) conducted by AIIMS New Delhi — not a separate JIPMER exam. The INI-CET PG exam has 300 MCQs covering all MBBS subjects, to be answered in 3 hours. However, JIPMER also conducts its own internal entrance tests for certain super-speciality programmes (DM/MCh) where the pattern varies by subject — typically a written exam followed by a direct interview. Check the JIPMER website for the latest super-speciality admission notifications.' },
    { question: 'What should I know about studying at JIPMER?', answer: 'JIPMER is unique among Indian medical institutions for several reasons: (1) It is directly under the Ministry of Health and Family Welfare — not under any state government; (2) There is no bond service requirement after MBBS unlike some state medical colleges; (3) The fee structure is significantly lower than private medical colleges — JIPMER MBBS fees are approximately ₹10,000–20,000 per year including hostel; (4) JIPMER has its own stipend for PG residents comparable to government medical colleges. JIPMER alumni are found in top medical positions globally, making it a highly sought-after institution despite the intense competition for admission.' },
  ],
  'gate': [
    { question: 'What is the GATE exam pattern?', answer: 'GATE consists of 65 questions worth 100 marks. The exam has two main sections: General Aptitude (15 marks, all candidates) and the subject-specific paper (85 marks). Questions are a mix of Multiple Choice Questions (MCQs) and Numerical Answer Type (NAT) questions. The exam is conducted online (CBT) in English only, for 3 hours.' },
    { question: 'What is the General Aptitude section in GATE?', answer: 'General Aptitude (GA) is a compulsory 15-mark section in every GATE paper — worth 15% of the total score. It covers Verbal Ability (4–5 questions on grammar, antonyms, analogies, reading comprehension) and Numerical Aptitude (8–9 questions on statistics, probability, algebra, geometry). Since every GATE aspirant faces GA, a strong foundation here reliably adds 10–13 marks at minimal effort compared to specialised subject study.' },
    { question: 'How is GATE score calculated?', answer: 'GATE uses a normalised score formula for multi-session papers. The raw score (out of 100) is converted to a GATE score out of 1000 using: GATE Score = 10 + (raw_score × 90/100). The qualifying cutoff varies by paper and category each year. For admission to M.Tech programmes in IITs/NITs, a GATE score of 650+ is generally competitive for top institutes; PSUs typically require 700–800+.' },
    { question: 'Which GATE paper should I attempt?', answer: 'Your GATE paper must align with your B.E./B.Tech discipline. Common papers: Computer Science (CS), Electronics & Communication (EC), Electrical (EE), Mechanical (ME), Civil (CE), Instrumentation (IN), and subject-specific papers like Chemistry (CY) or Physics (PH). The General Aptitude section is the same for all — StudyRoadmap covers all GA topics regardless of your engineering branch.' },
  ],
  'ugc-net': [
    { question: 'What is UGC NET and what does it qualify you for?', answer: 'UGC NET (University Grants Commission National Eligibility Test) is conducted by NTA for candidates seeking admission to Assistant Professor positions or wanting to pursue a PhD in Indian universities. Clearing UGC NET with a valid score makes you eligible to apply for lecturer and assistant professor posts across universities and colleges in India. The exam is conducted twice a year (June and December cycles) in over 80 subjects.' },
    { question: 'What is the UGC NET exam pattern?', answer: 'UGC NET consists of three papers conducted in a single session of 3 hours and 20 minutes. Paper 1 (100 questions, 200 marks) tests General Aptitude — teaching/research methodology, reasoning, and divergent thinking. Paper 2 (100 questions, 200 marks) covers the specific subject selected by the candidate. Both papers are objective MCQs. There is no negative marking. The exam is conducted online (CBT) at designated test centres.' },
    { question: 'What is the qualifying criteria for UGC NET?', answer: 'To qualify UGC NET, candidates must score at least 40% aggregate marks in both papers for the General category (35% for OBC/SC/ST/PwD). However, qualifying only makes you eligible for the NET certificate — actual recruitment depends on the cutoff set by individual universities and colleges. For a competitive score, aim for 180+ in Paper 1 and 180+ in your subject paper (out of 200 each). A score above 200 in both papers places you in the top tier for university recruitment.' },
  ],
  'gre': [
    { question: 'What is GRE and which universities accept it?', answer: 'The GRE (Graduate Record Examination) is a standardised test required for admission to graduate and business school programmes globally — particularly in the USA, Canada, UK, Europe, and parts of Asia. It measures analytical writing, verbal reasoning, and quantitative reasoning skills. Most top universities for MS, MBA, and PhD programmes require GRE scores as part of the application. It is administered by ETS and available year-round at test centres worldwide.' },
    { question: 'What is the GRE exam pattern?', answer: 'GRE consists of three sections: Analytical Writing (1 task, 30 minutes, scored 0–6), Verbal Reasoning (2 sections of ~27 questions each, 41 minutes total, scored 130–170), and Quantitative Reasoning (2 sections of ~27 questions each, 47 minutes total, scored 130–170). The exam is adaptive — performance in the first Verbal/Quant section determines difficulty of the second. An unidentified research section may also appear. Total duration is approximately 3 hours 45 minutes including breaks.' },
    { question: 'What is a good GRE score?', answer: 'Most top graduate programmes look for 320+ out of 340 (165+ in Verbal and 165+ in Quant). For competitive programmes at top-tier universities (MIT, Stanford, Ivy League), 330+ is typically expected. Business schools often focus more on the Quant score for engineering programmes (165+ preferred) and Verbal score for humanities/business programmes. Always check the specific programme requirements — some universities have minimum cutoffs or use GRE scores only for screening.' },
  ],
  'gmat': [
    { question: 'What is GMAT and which MBA programmes require it?', answer: 'GMAT (Graduate Management Admission Test) is the world\'s most widely used entrance exam for MBA and Master\'s in Finance programmes at top business schools globally. It is accepted by over 2,400 business schools in 110+ countries — including Harvard, Wharton, INSEAD, London Business School, ISB (India), and IIMs. GMAT is specifically designed for management education — it tests the skills needed for business school success. The exam is administered by GMAC and available year-round at test centres or online (GMAT Online). A GMAT score is valid for 5 years.' },
    { question: 'What is the GMAT exam pattern?', answer: 'GMAT consists of four sections: Quantitative Reasoning (31 questions, 62 minutes, scores 6–51) — covering Problem Solving and Data Sufficiency; Verbal Reasoning (36 questions, 65 minutes, scores 6–51) — covering Reading Comprehension, Critical Reasoning, and Sentence Correction; Integrated Reasoning (12 questions, 30 minutes, scores 1–8) — covering Multi-Source Reasoning, Table Analysis, Graphics Interpretation, and Two-Part Analysis; and Analytical Writing Assessment (1 essay, 30 minutes, scored 0–6). The total exam is approximately 2 hours 15 minutes. The Quant and Verbal sections are individually adaptive — wrong answers in Section 1 determine Section 2 difficulty.' },
    { question: 'What is a good GMAT score for top MBA programmes?', answer: 'A GMAT score of 700+ out of 800 is generally considered competitive for top 20 global MBA programmes. For the most selective schools (Harvard, Stanford, Wharton, INSEAD), 720+ is typical for admitted candidates. For Indian schools (ISB, IIM A/B/C), 700+ is the benchmark for the top cohort. The GMAT percentile matters — a 700 score is approximately the 88th percentile. Most top schools look at the full profile (GMAT, GPA, work experience, essays, recommendations) rather than GMAT alone. A strong GMAT score can compensate for a lower GPA or vice versa.' },
  ],
  'toefl': [
    { question: 'What is TOEFL and which universities require it?', answer: 'TOEFL (Test of English as a Foreign Language) is the world\'s most widely accepted English language proficiency test for academic admissions. It is accepted by over 12,000 universities and institutions in more than 160 countries — including virtually all universities in the USA, UK, Canada, Australia, and Europe for undergraduate and postgraduate admissions. Unlike IELTS, TOEFL is exclusively managed by ETS (Educational Testing Service). For international students whose first language is not English, a TOEFL score is often a mandatory part of the university application alongside SAT/ACT (undergraduate) or GRE/GMAT (postgraduate).' },
    { question: 'What is the TOEFL iBT exam pattern?', answer: 'TOEFL iBT (internet-based test) consists of 4 sections: Reading (35 minutes, 2 academic passages with 20 questions), Listening (36 minutes, 3–4 academic lectures and conversations), Speaking (16 minutes, 4 tasks — 1 independent + 3 integrated tasks), and Writing (29 minutes, 2 tasks — 1 integrated reading/listening/writing + 1 independent essay). Total duration is approximately 2 hours. The exam is conducted online at designated test centres. TOEFL MyBest Scores allows you to combine your best section scores from all TOEFL test attempts in the past 2 years — accepted by most universities. There is no penalty for wrong answers.' },
    { question: 'What TOEFL score do I need for university admission?', answer: 'Most US and UK universities require a minimum TOEFL score of 80–100 (out of 120). For top universities (Ivy League, Russell Group), 100+ is typically expected. For conditional admissions with English language preparation, many universities accept 70–80 with an offer of attending their pre-sessional English programme. A score of 90+ is generally competitive for most programmes; 100+ is needed for scholarship eligibility. Unlike IELTS which uses a 9-band scale, TOEFL uses a 0–120 scale. Always check the specific university\'s minimum requirement — some specify minimum scores for individual sections (e.g., Reading 20, Listening 20, Speaking 22, Writing 21).' },
  ],
  'pte': [
    { question: 'What is PTE Academic and why is it popular?', answer: 'PTE Academic (Pearson Test of English Academic) is a computer-based English language proficiency test accepted by universities, governments, and immigration authorities worldwide. It is particularly popular in Australia and New Zealand for both university admissions and student visa applications — Australian and New Zealand immigration authorities (DHA and INZ) accept PTE for subclass 500 student visas and skilled migration visas. PTE is also accepted by most UK universities (including Russell Group), many US universities, and European institutions. The test is fully automated — from speaking to scoring — removing human bias and delivering results within 48 hours.' },
    { question: 'What is the PTE exam pattern?', answer: 'PTE Academic consists of 3 parts taken in 2 hours: Part 1 — Speaking & Writing (77–93 minutes): Read aloud, repeat sentence, describe image, re-tell lecture, short answer questions, essay writing (20 minutes, 200–300 words). Part 2 — Reading (32–41 minutes): Multiple-choice questions (single and multiple answer), reorder paragraphs, fill in the blanks. Part 3 — Listening (45–57 minutes): Summarise spoken text, multiple-choice questions, fill in the blanks, highlight correct summary. All responses are AI-scored by Pearson\'s automated system. Questions are integrated — testing multiple skills simultaneously.' },
    { question: 'What PTE score do I need and how does it compare to IELTS?', answer: 'Most universities require a PTE score of 50–63 (out of 90) for undergraduate admissions. For top universities and scholarship eligibility, 65+ is preferred. For Australian and New Zealand student visas (subclass 500), the standard requirement is 50 or above. PTE uses a 90-band scale (similar to IELTS 9-band scale). PTE vs IELTS: PTE is entirely computer-based (no human examiner for speaking), faster results (48 hours vs 3–5 days), more integrated questions, and some students find PTE slightly easier due to its predictable format. However, both are equally accepted by universities and immigration authorities. Choose PTE if you prefer computer-based testing and need fast results.' },
  ],
  'ielts': [
    { question: 'What is IELTS and which countries accept it?', answer: 'IELTS (International English Language Testing System) is the world\'s most popular English language proficiency test — accepted by over 11,000 organisations in 140+ countries for study, work, and migration. It is particularly the standard requirement for universities and immigration in the UK, Australia, New Zealand, Canada, and Ireland. IELTS is jointly managed by the British Council, IDP Education, and Cambridge Assessment. There are two versions: IELTS Academic (for university admissions) and IELTS General Training (for work visas and migration). For university admissions, always take IELTS Academic.' },
    { question: 'What is the IELTS exam pattern?', answer: 'IELTS Academic consists of 4 sections taken in 2 hours 45 minutes: Listening (30 minutes, 40 questions — 4 recordings of conversations and monologues), Reading (60 minutes, 40 questions — 3 academic texts, academic reading passages), Speaking (11–14 minutes — face-to-face interview with an examiner covering introduction, long turn, and discussion), and Writing (60 minutes — Task 1: describe a graph/table/chart in 150 words; Task 2: essay in 250 words). Both Listening and Speaking are the same for Academic and General Training. Results are reported on a 9-band scale (1 = non-user, 9 = expert).' },
    { question: 'What IELTS score do I need and how is it scored?', answer: 'Most universities require an IELTS Academic score of 6.0–6.5 (overall) with no band below 5.5–6.0. Top universities (Ivy League, Russell Group, Group of 8 Australia) typically require 6.5–7.0 overall. For immigration (Australian PR, Canadian PR, UK work visa), the requirement is typically 6.0 overall. IELTS uses a 9-band scale — each section is scored 1–9 and the overall score is the average of the four sections. Results are valid for 2 years. Key tip: the speaking and writing sections are marked by trained examiners — practise with official IELTS practice materials and consider joining a test preparation course.' },
  ],
  'ctet': [
    { question: 'What is CTET and is it mandatory for teaching jobs?', answer: 'CTET (Central Teacher Eligibility Test) is conducted by CBSE (Central Board of Secondary Education) for candidates aspiring to become teachers in government schools (KVs, NVs, CBSE-affiliated private schools) in India. It is not mandatory for all teaching jobs — private schools may or may not require it. However, for government teaching positions, clearing CTET is a mandatory eligibility requirement under the CBSE guidelines. The test is conducted twice a year (typically July and December) and the certificate is valid for 7 years.' },
    { question: 'What is the CTET exam pattern?', answer: 'CTET has two papers — Paper 1 (for teachers of Class 1–5) and Paper 2 (for teachers of Class 6–8). Paper 1 covers Child Development & Pedagogy (30 questions), Language I (30 questions), Language II (30 questions), Mathematics (30 questions), and Environmental Studies (30 questions) — 150 questions in 150 minutes. Paper 2 covers Child Development & Pedagogy (30 questions), Language I (30 questions), Language II (30 questions), Mathematics & Science (60 questions) OR Social Studies (60 questions) — 150 questions in 150 minutes. There is no negative marking.' },
    { question: 'What is a good CTET score for teacher recruitment?', answer: 'To qualify CTET, candidates need 60% aggregate marks (90 out of 150) for the General category — 55% for OBC, 50% for SC/ST. However, qualifying CTET alone does not guarantee a teaching job — it only makes you eligible. Schools then shortlist candidates based on their CTET score, academic qualifications, and interview performance. A score above 90 (60%+ margin) is generally considered competitive and improves your chances of being shortlisted. Many states also accept CTET scores for their state teaching recruitments.' },
  ],
  'uptet': [
    { question: 'What is UPTET and how does it differ from CTET?', answer: 'UPTET (Uttar Pradesh Teacher Eligibility Test) is conducted by the UP Basic Education Board (UPBEB) for candidates aspiring to teach in Uttar Pradesh government schools — from Class 1 to Class 8. While CTET is a national-level certification accepted across India, UPTET is specifically for Uttar Pradesh state government teaching posts. However, qualifying UPTET also makes a candidate eligible for teaching jobs in some other state boards that recognise it. UPTET is conducted in both Hindi and English — the question paper is available in both languages. Passing UPTET is mandatory for applying to teacher vacancies in UP government schools.' },
    { question: 'What is the UPTET exam pattern?', answer: 'UPTET has two papers: Paper 1 (for teachers of Class 1–5) and Paper 2 (for teachers of Class 6–8). Paper 1 covers Child Development & Pedagogy (30 questions), Language I — Hindi (30 questions), Language II — English/Urdu/Sanskrit (30 questions), Mathematics (30 questions), and Environmental Studies (30 questions) — 150 questions in 150 minutes. Paper 2 covers Child Development & Pedagogy (30 questions), Language I — Hindi (30 questions), Language II — English/Urdu/Sanskrit (30 questions), Mathematics & Science (60 questions) OR Social Studies (60 questions) — 150 questions in 150 minutes. There is no negative marking. Each correct answer carries 1 mark.' },
    { question: 'What is the UPTET qualifying criteria and validity?', answer: 'To qualify UPTET, candidates need 60% aggregate marks (90 out of 150) for the General category — 55% for OBC, 50% for SC/ST. The UPTET certificate is valid for 5 years (unlike CTET\'s 7 years). After qualifying, candidates can apply for teacher vacancies in UP government schools under the UP Basic Shiksha service. Some private schools in UP also require UPTET as a minimum qualification. UPTET is distinct from UP TET — some coaching centres incorrectly use these terms interchangeably.' },
  ],
  'cuet-ug': [
    { question: 'What is CUET and why does it matter?', answer: 'CUET (Common University Entrance Test) is a single-window exam for admission to undergraduate programmes at all Central Universities, deemed universities, and many private universities across India. Since 2022, it has replaced individual university entrance exams for most central universities — appearing for CUET is the only way to get into most central universities through the CUET channel.' },
    { question: 'How is CUET scored?', answer: 'CUET uses a normalisation process because the exam is conducted in multiple shifts with different question papers. Your raw score in each section is converted to a percentile score. Admission cutoffs are prepared using these normalised percentiles. Each university sets its own cutoff for each programme — check the specific university you are targeting to know the expected score.' },
    { question: 'What is a good CUET score?', answer: 'A score above the 80th percentile (approximately 200–220 out of 300 in best 3 subjects) is generally competitive for mid-tier central universities. Top universities like Delhi University (DU) and Banaras Hindu University (BHU) typically require 85th–95th percentile depending on the programme. Aim for at least 90th percentile if targeting the top central universities.' },
  ],
  'cuet-pg': [
    { question: 'What is CUET-PG and how does it differ from CUET-UG?', answer: 'CUET-PG (Postgraduate) is the master\'s-level entrance exam conducted by NTA for admission to PG programmes at central universities, deemed universities, and other participating institutions across India. Unlike CUET-UG (undergraduate), CUET-PG tests subject-specific knowledge at the graduate level — candidates choose one paper from their relevant discipline (e.g., History, Mathematics, English, Commerce). While CUET-UG covers Class 12 syllabus, CUET-PG covers the undergraduate degree syllabus of the respective subject. It has replaced individual university-level PG entrance exams for most central universities.' },
    { question: 'What is the CUET-PG exam pattern?', answer: 'CUET-PG consists of a single discipline-specific paper of 100 questions to be answered in 2 hours (120 minutes). Each question carries 4 marks; 1 mark is deducted for each wrong answer. The questions are multiple-choice and test domain knowledge at the graduate level. Some universities accept CUET-PG scores for multiple PG programmes (e.g., History, Political Science, and Public Administration may fall under the same subject code). The exam is conducted online (CBT) at designated test centres across India and abroad.' },
    { question: 'What is a good CUET-PG score for top universities?', answer: 'For admission to top central universities (DU, BHU, JNU, AMU), a percentile above 80 (approximately 200+ out of 300) is generally competitive for most programmes. For highly competitive courses like History, Economics, or English at top universities, a percentile above 90 is preferred. Since CUET-PG uses normalised scores, the exact marks-to-percentile conversion varies by session and subject. Universities publish discipline-specific cutoffs after each admission cycle — check the previous year\'s cutoffs for your target programme as a benchmark.' },
  ],
  'du-adm': [
    { question: 'What is DU-ADM and how does it work?', answer: 'DU-ADM (Delhi University Admissions) refers to the separate entrance tests conducted by Delhi University for specific undergraduate programmes that are not covered under CUET. These include Bachelor of Business Economics (BBE), Bachelor of Financial Economics (BFE), Journalism (MJ), and some Honours programmes in specific colleges that conduct their own tests. After CUET became mandatory for most DU programmes in 2022, these remaining courses still use college-level entrance exams. Each college sets its own exam pattern and cutoff. Check the specific college\'s website for the current year\'s admission process.' },
    { question: 'What is the DU-ADM exam pattern for BBE and BFE?', answer: 'The DU-ADM tests for BBE (Bachelor of Business Economics) and BFE (Bachelor of Financial Economics) typically consist of 100 multiple-choice questions to be answered in 2 hours. The syllabus covers: Quantitative Aptitude (Class 11-12 Mathematics: Arithmetic, Algebra, Calculus basics), Economics (Microeconomics, Macroeconomics at introductory level), General Awareness and Current Affairs, and English Language and Logical Reasoning. Each correct answer carries 4 marks; 1 mark is deducted for each wrong answer in some years. The exam is conducted at designated centres in Delhi.' },
    { question: 'How do I prepare for DU-ADM entrance tests?', answer: 'DU-ADM entrance tests are less standardised than CUET — each college has its own pattern and difficulty. For BBE/BFE: focus on Class 11-12 Mathematics (particularly Calculus, Arithmetic, and Algebra), introductory Micro/Macroeconomics, and current affairs. For Journalism (MJ): focus on English language skills, current affairs, and media awareness. Solving previous year question papers (available on college websites or online forums) is the most effective preparation strategy. Since CUET now handles most DU admissions, these entrance tests have smaller candidate pools — a well-prepared candidate has a strong chance.' },
  ],
  'ege': [
    { question: 'What is EGE and who is it for?', answer: 'EGE (Единый государственный экзамен, Unified State Examination) is Russia\'s standardised school-leaving exam — the equivalent of A-Levels or the WASSCE. It is the mandatory exam for completing Russian secondary education (Grade 11) and is the primary basis for university admission in Russia. Every student completing secondary school in Russia must take EGE to receive their school certificate and qualify for university admission. For international students, EGE results are used for admission to Russian universities, particularly for government scholarship programmes (quota spots) under the Russian Government Scholarship programme for foreign nationals.' },
    { question: 'What is the EGE exam structure?', answer: 'EGE consists of compulsory exams and elective exams. Compulsory: Russian Language (written, 3 hours) and Mathematics (Base level or Profitable level). Electives for university admission typically include: Physics, Chemistry, Biology, History, Social Science, Computer Science, Geography, and Foreign Languages. Each exam has two parts: a written test and an oral interview (for Russian Language). Exams are scored on a 100-point scale; university admission cutoffs are set by individual universities each year. The exam season runs May–June for school graduates; international students can take EGE at designated centres abroad or in Russia.' },
    { question: 'How do international students use EGE for Russian university admission?', answer: 'International students can gain admission to Russian universities through EGE results, particularly for government quota scholarships (currently about 15,000 scholarship slots per year for foreign nationals). The application process: (1) Take EGE in required subjects — most popular for international students: Mathematics, Physics, Chemistry, Biology (for medicine), or History/Social Science. (2) Apply through the Russian Government Scholarship portal (Russia.StudyinRussia.ru) typically Jan–Mar for the following academic year. (3) Submit EGE certificates to your chosen universities. Minimum passing score is 24/100 for most subjects; competitive programmes (medicine, engineering at top universities like Moscow State University, Sechenov Medical University) typically require 70–85+. English-taught programmes in Russia also require an English proficiency test.' },
  ],
  'gaokao': [
    { question: 'What is GAOKAO and why is it important?', answer: 'GAOKAO (高考, Hanyu Pinyin: Gāokǎo, literally "High School Exam") is China\'s national university entrance examination — one of the most important and pressurised exams in the world. Taken by over 10 million students annually, it is the sole determinant of admission to Chinese universities for undergraduate programmes. The exam is administered by the Ministry of Education and is taken over 2–3 days in June every year. A student\'s GAOKAO score (combined with their high school record) determines which universities and programmes they can apply to. It is famously intense — Chinese universities are ranked primarily by admission cutoffs, and scoring well in GAOKAO is seen as life-defining.' },
    { question: 'What is the GAOKAO exam structure?', answer: 'GAOKAO consists of 3 mandatory subjects plus optionalElective subjects: Mandatory: Chinese (Mathematics is also mandatory, 150 marks each, 2.5 hours), and Foreign Language (English, Japanese, Russian, or German — 150 marks, 2 hours). Electives for Science stream: Physics, Chemistry, Biology. Electives for Arts stream: History, Geography, Political Science. Each province sets its own papers within the national framework. Total scores vary by province — typically 750 is the maximum. The exam is conducted over 2–3 days consecutively, in designated high school centres. Shanghai and Beijing use a 3+3 model (3 mandatory + 3 elective from 20 options).' },
    { question: 'How do international students use GAOKAO for Chinese university admission?', answer: 'International students have several pathways to Chinese universities: (1) Direct admission using GAOKAO — some universities accept international students with GAOKAO scores (typically 70% or above of the maximum). (2) Chinese Government Scholarship (CSC) — requires GAOKAO score plus an HSK (Chinese language) certificate; awarded to top international students for tuition-free education. (3) Individual university programmes — universities like Peking University, Tsinghua, Fudan, and Zhejiang University have dedicated international student admissions requiring GAOKAO + HSK 4–6 + interview. Most international undergraduate programmes in China are taught in Chinese and require HSK 4+. Medicine programmes (MBBS in English) at universities like Shanghai Jiao Tong and Fudan accept international students through a separate pathway without GAOKAO.' },
  ],
  'rbi-grad-b': [
    { question: 'What is RBI Grade B and why is it prestigious?', answer: 'RBI Grade B (Officers in Reserve Bank of India) is one of the most sought-after banking sector jobs in India — it comes with a gross monthly salary of around ₹77,000–₹82,000 plus allowances, with promotion potential to the highest levels of the RBI. Unlike bank PO jobs, RBI Grade B officers work directly in monetary policy, economic research, financial regulation, and currency management.' },
    { question: 'How tough is RBI Grade B Phase 2?', answer: 'RBI Grade B Phase 2 (Mains) is considered one of the toughest descriptive exams in the Indian banking sector. It has three papers: Economic & Social Issues (ESI, 100 marks, descriptive), Finance & Management (FM, 100 marks, descriptive), and English (Descriptive Writing, 100 marks). The descriptive nature makes it challenging — candidates must write structured answers in limited time. StudyRoadmap covers all ESI and FM topics with Quick/Standard/Deep tiers.' },
    { question: 'How should I prepare for RBI Grade B ESI and Finance?', answer: 'Start with the RBI Annual Report and Budget Economic Survey for ESI. For Finance, focus on financial management, accounting, and banking topics. The Phase 2 cutoff for General category typically ranges between 130–150 out of 300. StudyRoadmap breaks down both ESI and Finance into 20 topics with three study tiers — start with Quick for overview, Standard for depth, and Deep for complete coverage.' },
  ],
  'ibps-po': [
    { question: 'What is IBPS PO and how does the selection process work?', answer: 'IBPS PO (Probationary Officer) is one of India\'s largest-scale banking sector recruitment exams, conducted annually by the Institute of Banking Personnel Selection (IBPS) for recruitment to public sector banks in India. The selection process has three stages: Preliminary (Tier 1, objective, qualifying), Mains (Tier 2, objective + descriptive), and a Common Interview Round (conducted post-mains for all qualifying candidates). After clearing all three, candidates are allocated to one of the 12 PSU banks based on merit and preference.' },
    { question: 'What is the IBPS PO exam pattern for Prelims and Mains?', answer: 'IBPS PO Prelims consists of three sections: Quantitative Aptitude (35 questions), Reasoning Ability (35 questions), and English Language (30 questions) — 100 questions total to be answered in 60 minutes. IBPS PO Mains has four sections: Reasoning & Computer Aptitude (45 questions), General/Economic/Banking Awareness (40 questions), English Language (35 questions), and Data Analysis & Interpretation (35 questions) — 155 questions in 180 minutes, plus a Descriptive Test (Letter and Essay writing, 25 marks).' },
    { question: 'What is a good score in IBPS PO?', answer: 'For IBPS PO Prelims, a score of 70–75 out of 100 is generally considered good for the General category to clear the cutoff. For Mains, a score of 120–130 out of 200 (objective) plus 18–20 out of 25 (descriptive) is competitive. After the interview, the final merit is calculated as: Mains marks (80%) + Interview (20%). Candidates in the top 100 ranks typically receive offers from premier banks. StudyRoadmap covers the complete IBPS PO syllabus across all three stages.' },
  ],
  'ibps-clerk': [
    { question: 'What is IBPS Clerk and how does it differ from IBPS PO?', answer: 'IBPS Clerk is a clerical-level banking exam conducted by IBPS for appointment as Clerk/Office Assistant in public sector banks across India — the largest clerical recruitment in the country. Unlike IBPS PO (which selects probationary officers), IBPS Clerk involves routine banking operations, customer service, and administrative work. The starting salary is typically ₹30,000–₹35,000 per month plus allowances. The selection process is two-stage: Preliminary (qualifying) followed by Mains (final merit), with no interview component — unlike PO.' },
    { question: 'What is the IBPS Clerk exam pattern?', answer: 'IBPS Clerk Prelims has three sections: English Language (30 questions), Numerical Ability (35 questions), and Reasoning Ability (35 questions) — 100 questions in 60 minutes. The Mains exam has four sections: Reasoning Ability & Computer Aptitude (50 questions), General/Financial Awareness (50 questions), English Language (40 questions), and Quantitative Aptitude (50 questions) — 190 questions in 160 minutes. There is negative marking of 0.25 marks per wrong answer in both Prelims and Mains.' },
    { question: 'Do I need an interview for IBPS Clerk?', answer: 'No — IBPS Clerk recruitment does not include an interview. The final merit list is prepared solely based on the Mains examination score. This makes it a two-stage process (Prelims + Mains) unlike IBPS PO which adds an interview round. The Prelims is only qualifying in nature; your Mains score determines your final rank and bank allocation. StudyRoadmap covers the complete IBPS Clerk syllabus for both Prelims and Mains.' },
  ],
  'ssc-cgl-tier2': [
    { question: 'What is SSC CGL Tier 2?', answer: 'SSC CGL Tier 2 is the Mains examination for Combined Graduate Level exam — it consists of two mandatory papers: Paper 1 (Quantitative Abilities, 100 questions, 200 marks) and Paper 2 (English Language & Comprehension, 200 questions, 200 marks). Both papers are online (CBT), objective, with negative marking of 0.25 marks per wrong answer.' },
    { question: 'How is SSC CGL scored in Tier 2?', answer: 'Tier 2 scores are normalised because of multi-shift papers. Your final merit is based on Tier 2 marks (weighted 200) combined with Tier 1 score (200 marks). For a score of 140+ in Tier 2 Quantitative Abilities (out of 200), focus on arithmetic, geometry, and data interpretation — these carry the most weight. English requires consistent practice on error detection, reading comprehension, and vocabulary.' },
    { question: 'What topics matter most in SSC CGL Tier 2?', answer: 'For Quantitative Abilities: Profit & Loss, Time & Work, Geometry, Trigonometry, and Data Interpretation consistently carry high weight. For English: Spotting Errors, Cloze Test, and Reading Comprehension are the highest-scoring sections. StudyRoadmap covers both papers with 12 topics each across Quick/Standard/Deep tiers to match your preparation level.' },
  ],
  'aiims-mbbs': [
    { question: 'What is AIIMS MBBS and how does it work?', answer: 'AIIMS (All India Institute of Medical Sciences) MBBS is India\'s most prestigious medical undergraduate entrance exam — admissions to the 25 AIIMS institutions across India are done purely on the basis of the AIIMS MBBS entrance exam rank. AIIMS New Delhi is the flagship, consistently ranked as India\'s top medical college. There are currently 25 AIIMS campuses: New Delhi, Bhopal, Bhubaneswar, Jodhpur, Nagpur, Patna, Raipur, Rishikesh, and 16 newer ones (Ballabgarh, Bhatinda, Bilaspur, Chengalpattu, Chhendiapur, Deoghar, Gorakhpur, Hyderabad, Jammu, Kalyani, Mangalagiri, Muzaffarnagar, Nagpur annex, Mangalore annex, Madurai annex, and Rajkot annex).' },
    { question: 'What is the AIIMS MBBS exam pattern?', answer: 'AIIMS MBBS consists of 200 multiple-choice questions to be answered in 3 hours and 30 minutes. The distribution is: Physics (60 questions), Chemistry (60 questions), Biology (60 questions, covering Botany and Zoology), and General Knowledge/Aptitude (20 questions). Each correct answer carries 1 mark; 0.33 marks are deducted for each wrong answer. There is no positive marking for the GK/Aptitude section in some years. The exam is conducted online (CBT) at designated centres across India.' },
    { question: 'What is a good AIIMS MBBS rank for admission?', answer: 'For AIIMS New Delhi, a rank within the top 50–100 is typically needed for the general category. For the newer AIIMS campuses (Tier 2), a rank within the top 1,000–2,000 is generally competitive. The AIIMS merit list is prepared based on the normalized percentile score. After the seat allocation process (conducted by MCC for AIIMS), candidates go through document verification and medical examination before admission. Candidates must score above 60–65% to be in the competitive range for any AIIMS campus.' },
  ],
  'ssc-cgl': [
    { question: 'What is SSC CGL Tier 1 and what does it test?', answer: 'SSC CGL Tier 1 is the Preliminary stage of the Combined Graduate Level exam — it is a qualifying exam and the first hurdle for all candidates. It consists of four sections: General Intelligence & Reasoning (25 questions), General Awareness (25 questions), Quantitative Aptitude (25 questions), and English Comprehension (25 questions). All 100 questions are objective MCQs, each carrying 2 marks. There is a negative marking of 0.50 marks per wrong answer. Candidates must score above the category-wise cutoff to qualify for Tier 2.' },
    { question: 'How tough is SSC CGL Tier 1 and what score should I target?', answer: 'SSC CGL Tier 1 is considered moderately difficult — with focused preparation, most graduates can clear it. For the General category, a score of 135–145 out of 200 is typically needed to qualify comfortably. The General Awareness section is the most unpredictable — questions range from current affairs to history, geography, and science. Quantitative Aptitude and Reasoning are more scoring with practice. StudyRoadmap provides topic-wise coverage for all four sections at Quick/Standard/Deep difficulty tiers.' },
    { question: 'What is the full SSC CGL selection process?', answer: 'SSC CGL has a four-tier selection process: Tier 1 (Prelims, 200 marks, qualifying), Tier 2 (Mains, 200+200 marks, main merit), Tier 3 (Descriptive Essay/Precis/Letter, 100 marks), and Tier 4 (Skill Test — DEST for Tax Assistant, CPT for Assistant Section Officer). The final merit is based on Tier 1 + Tier 2 marks for most posts. Posts like Assistant Section Officer also require Tier 4 DEST. After clearing all tiers, candidates go through Document Verification before appointment.' },
    { question: 'ssc cgl 2026 notification', answer: 'The SSC CGL 2026 notification is expected to be published in March 2026 on the official SSC website (ssc.nic.in). The SSC CGL exam is conducted annually for recruitment to Group B and C posts in various ministries and departments of the Government of India. The notification will include details about exam dates, eligibility, vacancy count, examination centres, and the online application process. Candidates should regularly check ssc.nic.in and ssc.gov.in for the latest updates and notifications.' },
    { question: 'ssc cgl 2026 result', answer: 'The SSC CGL 2026 result is expected to be declared 2–3 months after the Tier 2 examination. Since SSC CGL is conducted in multiple stages (Tier 1, Tier 2, Tier 3, Tier 4), the final result for the combined merit list is typically declared within 6–8 months of the Tier 1 exam. Tier 1 result for the 2026 cycle is expected around mid-2026, with Tier 2 following 2–3 months later. The result can be checked on the official SSC website (ssc.nic.in) using the candidate\'s registration number and date of birth.' },  ],
  'tnpsc': [
    { question: 'What is TNPSC and how does it work?', answer: 'TNPSC (Tamil Nadu Public Service Commission) conducts Group 1, 2, 3, and 4 examinations for recruitment to civil services and administrative posts in the Tamil Nadu state government. The Combined Engineering Services Examination (CESE) is the engineering-specific recruitment under Group 4. TNPSC exams are conducted in Tamil Nadu for positions like Assistant Engineer (Civil/Electrical/Mechanical), Junior Engineer, and other state government posts. Candidates must be Tamil Nadu residents or graduates from Tamil Nadu institutions to be eligible for most posts.' },
    { question: 'What is the TNPSC exam pattern?', answer: 'TNPSC Group 4 consists of a single written examination of 300 questions to be answered in 3 hours. The paper covers: General Studies (200 questions, covering history, geography, science, polity, economics, current affairs), Aptitude & Mental Ability (25 questions), General English (25 questions), and General Tamil (50 questions — candidates choose between Tamil and English for this section). All questions are objective MCQs. There is a negative marking of 0.25 marks per wrong answer. The exam is conducted in both Tamil and English medium.' },
    { question: 'What is a good TNPSC score and how does selection work?', answer: 'A score of 180–200 out of 300 is generally considered competitive for the General category. For the Engineer posts (Group 4 CESE), the selection is based on marks obtained in the written exam alone — there is no interview. The rank list is prepared and allocated to departments based on preference and vacancy. After being allocated, candidates undergo document verification and medical examination before appointment. TNPSC Group 4 posts include roles like Junior Engineer (Civil), Assistant, and VAO (Village Administrative Officer) — each with different eligibility criteria.' },
  ],
  'kpsc': [
    { question: 'What is KPSC and how does it work?', answer: 'KPSC (Karnataka Public Service Commission) conducts the Gazetted Probationers Examination (Group A & B) and the Departmental Examination for recruitment to civil services and administrative posts in the Karnataka state government. The KPSC Gazetted Probationers exam is one of the most competitive state-level exams in Karnataka — covering posts like Deputy Collector, Assistant Commissioner, Tahsildar, and other Group A/B gazetted posts. Karnataka degree holders or Karnataka domicile candidates get preference under the local candidate rules.' },
    { question: 'What is the KPSC exam pattern?', answer: 'KPSC Gazetted Probationers (Group A & B) consists of two compulsory papers and one optional paper: Paper 1 — General Studies (200 marks, 2 hours, covering history, geography, economics, Karnataka polity, science, current affairs), Paper 2 — General Kannada (100 marks, 1.5 hours, language comprehension and grammar), and Paper 3 — English (100 marks, 1.5 hours). For Group C posts, KPSC conducts a Computer Based Test (CBT) with objective questions. The Preliminary exam acts as a screening test for the Mains exam. There is negative marking in both stages.' },
    { question: 'How does KPSC selection and counselling work?', answer: 'For KPSC Gazetted Probationers, candidates who clear the Preliminary exam appear for Mains, followed by an interview. The final merit list combines Mains marks (typically 75%) and Interview marks (25%). Based on rank and preference, candidates are allocated to departments and districts. The Karnataka Administrative Service (KAS) is the flagship service recruited through KPSC. After selection, probationers undergo training at the Karnataka Institute of State. KPSC also recruits for Group C and D posts through separate examination cycles with their own patterns.' },
  ],
  'cds': [
    { question: 'What is CDS and how does it work?', answer: 'CDS (Combined Defence Services) is a national-level entrance exam conducted by UPSC twice a year for admission to the Indian Military Academy (IMA), Indian Naval Academy (INA), Air Force Academy (AFA), and Officers Training Academy (OTA). It is one of the most prestigious defence examinations in India — candidates cleared in both the written exam and SSB interview receive a Short Service Commission or Permanent Commission in the Indian Armed Forces. Only unmarried candidates are eligible for IMA, INA, and AFA; OTA accepts married candidates.' },
    { question: 'What is the CDS exam pattern?', answer: 'CDS consists of three papers, each of 2 hours duration: Paper 1 — English (100 marks, grammar, vocabulary, reading comprehension), Paper 2 — General Knowledge (100 marks, current affairs, history, geography, science), and Paper 3 — Elementary Mathematics (100 marks, for IMA/INA/AFA only — not required for OTA). All papers are objective MCQs. The exam is conducted offline (pen-and-paper) at centres across India. For OTA, only English and General Knowledge papers are applicable.' },
    { question: 'How does CDS SSB selection work?', answer: 'Candidates who clear the written exam are called for the 5-day SSB interview at one of the SSB centres (Bhopal, Allahabad, Dehradun, Bangalore, or Lucknow). The SSB consists of two stages: Stage I (OIR — Officer Intelligence Rating — and Picture Perception) and Stage II (Psychological Tests, Group Testing tasks, Personal Interview, and Conference). The SSB interview carries 300 marks for IMA/INA/AFA and 200 marks for OTA. The final merit list is prepared by combining written exam marks and SSB interview marks. Medical fitness is also a requirement.' },
  ],
  'bitsat': [
    { question: 'What is the eligibility for BITSAT?', answer: 'Candidates must have passed Class 12 with at least 75% aggregate marks in Physics, Chemistry, and Mathematics (PCM), with at least 60% in each subject individually. However, appearing for BITSAT does not require this threshold — only admission does. Students currently appearing in Class 12 are also eligible to appear. There is no age limit for BITSAT.' },
    { question: 'What is the BITSAT exam pattern?', answer: 'BITSAT is a computer-based test of 3 hours with 150 multiple-choice questions divided into 4 sections: Physics (40 questions), Chemistry (40 questions), Mathematics (45 questions), and English & Logical Reasoning (25 questions). There is no negative marking for wrong answers. The exam is conducted in English only. Candidates who score 300 or above out of 450 are considered competitive for BITS Pilani campus admissions.' },
    { question: 'How does BITSAT counselling work?', answer: 'BITSAT counselling is conducted through JOSAAC (Joint Seat Allocation Authority) for admission to BITS Pilani, Hyderabad, and Goa campuses. After BITSAT results are declared, candidates fill their preferences online. Seat allocation is done in multiple rounds based on rank, preferences, and availability. The BTech programme at BITS offers flexibility to switch branches after the first year based on CGPA.' },
  ],
  'bpsc': [
    { question: 'What is BPSC and how does it work?', answer: 'BPSC (Bihar Public Service Commission) conducts the Combined Competition Examination (CCE) — the premier civil service exam for Bihar. It recruits for positions like District Collector, Sub-Divisional Officer, Superintendent of Police, and various Bihar Administrative Service posts. BPSC CCE has three stages: Preliminary (screening), Mains (written), and Interview. Bihar domicile is preferred but not always mandatory. BPSC is one of the most competitive state-level exams in India, with over 1 lakh candidates appearing for the Prelims each year.' },
    { question: 'What is the BPSC exam pattern?', answer: 'BPSC Prelims consists of a single General Studies paper (150 questions, 300 marks, 2 hours) covering history, geography, polity, economy, science, and current affairs — with a strong emphasis on Bihar-specific issues. The Mains has 4 compulsory papers: General Studies Paper 1 (200 marks), General Studies Paper 2 (200 marks), General Hindi (100 marks), and an optional subject paper (200 marks). All Mains papers are descriptive. There is negative marking of 1.33 marks in Prelims per wrong answer.' },
    { question: 'How tough is BPSC and what should I target?', answer: 'BPSC Prelims typically has a cutoff of 45–55% for the General category, varying by year. Out of 1 lakh+ candidates, around 5–7% qualify for Mains. The Mains exam is where the real competition happens — candidates must score well in all four papers to reach the Interview stage. A rank within the top 100 is generally needed for the most coveted Bihar Administrative Service postings. Focus heavily on Bihar-specific history, geography, and current affairs — these frequently appear and can make the difference.' },
  ],
  'ras': [
    { question: 'What is RAS and how does it work?', answer: 'RAS (Rajasthan Administrative Service) is the premier civil service of Rajasthan — recruited through the RPSC (Rajasthan Public Service Commission) Combined Services Examination. It is one of the most prestigious state-level competitive exams in India, attracting over 1 million applicants each cycle. RAS officers serve as District Collectors, Additional District Magistrates, Sub-Divisional Magistrates, and in various state-level departments. The examination covers three stages: Preliminary (screening), Main (written), and Interview. After selection, RAS officers undergo training at the Rajasthan Institute of State before being allocated to districts and departments.' },
    { question: 'What is the RAS exam pattern?', answer: 'RAS Preliminary consists of one General Knowledge paper (200 questions, 3 hours) covering history, geography, politics, economy, science, technology, and current affairs of Rajasthan, India, and the world. The Mains has four papers: Paper 1 — General Knowledge & General Science (200 marks), Paper 2 — General Studies of Rajasthan (200 marks, focus on history, art, culture, geography, polity of Rajasthan), Paper 3 — General Studies of India and World (200 marks), and Paper 4 — General Hindi, Elementary Hindi Grammar, and English (200 marks). All papers are descriptive/short-answer except the Preliminary which is objective.' },
    { question: 'How tough is RAS and what should I target?', answer: 'RAS Preliminary has a typical cutoff of 40–45% for the General category, but the actual marks needed vary by year. The real competition is in the Mains — out of ~15,000 who clear Prelims, only ~2,000 reach the Interview stage. For selection, a Mains score above 400 out of 800 is competitive for the merit list. Since all four Mains papers are descriptive, answer writing practice is essential — the Rajasthan-specific Paper 2 often differentiates top rankers. StudyRoadmap covers RAS General Studies and Hindi papers with structured topic notes.' },
  ],
  'xat': [
    { question: 'What is XAT and which B-schools accept it?', answer: 'XAT (Xavier Aptitude Test) is a national-level MBA entrance exam conducted by XLRI Jamshedpur on behalf of the Xavier Association of Management Institutes (XAMI). It is accepted by over 150 B-schools across India, including XLRI Jamshedpur (its primary caller), XIMB (Bhubaneswar), Great Lakes Institute of Management (Chennai), IMT Dubai, and many other premier private B-schools. XAT is known for its emphasis on decision-making skills and is preferred by candidates targeting XLRI\'s HR and Business programmes.' },
    { question: 'What is the XAT exam pattern?', answer: 'XAT consists of three main sections: Verbal & Logical Ability (26 questions), Decision Making (22 questions), and Quantitative Ability & Data Interpretation (28 questions) — 76 questions total in 165 minutes. Additionally, there is a General Knowledge section (25 questions) and an Essay Writing section — both separately timed and not counted for percentile calculation but reviewed during interviews. There is a negative marking of 0.25 marks per wrong answer for the first three sections. The exam is conducted online (CBT) once a year, typically in early January.' },
    { question: 'What is a good XAT score?', answer: 'A score above 95 percentile (approximately 35+ out of 76) is considered competitive for shortlisting by XLRI Jamshedpur. For XLRI HRM, a score above 99 percentile is typically needed. For other top XAT-accepting schools like XIMB, Great Lakes, and IMT, 85–90 percentile is generally sufficient for shortlisting. The Decision Making section is unique to XAT and carries significant weight — strong performance here can compensate for weaker Quant or Verbal scores. After shortlisting, WAT and PI rounds determine final selection.' },
  ],
  'snap': [
    { question: 'What is SNAP and which colleges accept it?', answer: 'SNAP (Symbiosis National Aptitude Test) is the entrance exam for the Symbiosis International University (SIU) group, which comprises 16 autonomous institutes including SCMHRD (Pune), SIBM (Pune), SITM (Pune), and others. SNAP is a moderate-difficulty MBA entrance exam that tests General English, Quantitative Data Interpretation & Reasoning, and General Awareness. Unlike CAT/XAT, SNAP uses a scaled percentile from multiple test sessions, and SIU colleges have their own group-specific GE-PIWAT rounds after shortlisting.' },
    { question: 'What is the SNAP exam pattern?', answer: 'SNAP consists of three sections: General English (15 questions), Quantitative Data Interpretation & Reasoning (20 questions), and General Awareness (15 questions) — 50 questions total to be answered in 60 minutes. Each question carries 1 mark; there is a negative marking of 0.25 marks per wrong answer. SNAP is conducted in multiple sessions (typically 3) between November and January each year. The best of up to 3 attempts is used for the final percentile calculation. Candidates can appear for all SNAP attempts and use their best score.' },
    { question: 'How does SNAP scoring and college admission work?', answer: 'SNAP scores are normalised across all sessions to produce a single scaled score and percentile. The percentile is used for shortlisting candidates for the GE-PIWAT (Group Exercise, Personal Interview, Written Ability Test) rounds at each SNAP college. Each SIU institute (SIBM, SCMHRD, SIMS, etc.) sets its own cutoff percentile for shortlisting — top institutes like SIBM Pune and SCMHRD typically require SNAP percentiles above 97–98. The final selection is based on the SNAP percentile (weight varies by institute, typically 50%) plus GE-PIWAT performance.' },
  ],
  'vitee': [
    { question: 'What is the VITEEE exam pattern?', answer: 'VITEEE consists of 125 multiple-choice questions to be answered in 2 hours 30 minutes (150 minutes) on a computer. The sections are: Physics (35 questions), Chemistry (35 questions), Mathematics/Biology (40 questions — candidates choose based on their stream), and English (10 questions). There is no negative marking. The exam is conducted online across multiple shifts. Candidates scoring above 90 out of 125 are generally in the competitive range for VIT Vellore.' },
    { question: 'What is the eligibility for VITEEE?', answer: 'Candidates must have completed Class 12 or appear in the current year with at least 60% aggregate in Physics, Chemistry, and Mathematics/Biology (PCB/PCM). For B.Tech Biotechnology at VIT, candidates from PCB stream are also eligible. There is no age limit for VITEEE. The exam is open to all Indian nationals as well as NRI and foreign nationals.' },
    { question: 'How is VITEEE rank calculated?', answer: 'VITEEE uses a normalised percentile score because the exam is conducted in multiple sessions with different papers. The rank is determined by the normalised score, not the raw marks. Candidates are ranked from 1 to approximately 1 lakh. Based on rank, counselling (MI-MIVIT) is conducted for admission to various BTech programmes at VIT Vellore, Chennai, Amaravati, and Bhopal campuses.' },
  ],
  'manipal-met': [
    { question: 'What is MET and which universities accept it?', answer: 'MET (Manipal Entrance Test) is conducted by Manipal Academy of Higher Education (MAHE) for admission to its flagship B.Tech programmes at MIT Manipal (the original and most prestigious Manipal institute), as well as Manipal University Jaipur and Manipal College of Pharmaceutical Sciences. MET is the only entrance exam accepted for Manipal\'s own programmes — unlike some universities that accept multiple scores. MET is conducted annually (typically May) in online (CBT) mode at centres across India and internationally. Over 50,000 students appear for MET each year, competing for approximately 2,000 B.Tech seats across all campuses.' },
    { question: 'What is the MET exam pattern?', answer: 'MET consists of 160 multiple-choice questions to be answered in 2 hours 30 minutes (150 minutes) on a computer. The sections are: Physics (50 questions), Chemistry (50 questions), Mathematics (50 questions), and English (10 questions). Each correct answer carries 4 marks; there is no negative marking. The exam is conducted online (CBT) in multiple shifts. Since there is no negative marking and all questions carry equal weight, candidates are encouraged to attempt all questions — even uncertain guesses carry a 25% chance of being correct. MET is generally considered easier than JEE Main in terms of difficulty level.' },
    { question: 'How does MET counselling and admission work?', answer: 'MET counselling is conducted by MAHE through its own centralised process (no JoSAA or state counselling). After MET results are declared, candidates fill their programme and campus preferences online. Seat allocation is based on MET rank, preferences, and availability. MIT Manipal offers B.Tech in all major branches including Computer Science, Electronics, Mechanical, Civil, and others. The fee structure at MIT Manipal is approximately ₹3–4 lakhs per semester (tuition only) — one of the more expensive private engineering colleges in India, but with strong placement records (top recruiters include Google, Microsoft, Amazon, Goldman Sachs). Students who score well in MET get first choice of campus and branch.' },
  ],
  'mht-cet': [
    { question: 'What is the MHT-CET exam pattern?', answer: 'MHT-CET (Maharashtra Common Entrance Test) consists of 200 multiple-choice questions: Physics (50 questions), Chemistry (50 questions), and Mathematics (100 questions). Each question carries 2 marks. There is no negative marking. The exam is conducted online (CBT) over approximately 3 hours. For PCB candidates, Biology replaces the Mathematics section with 100 questions. The exam is tougher than HSC board exams — approximately 20% of questions are from Class 11 curriculum.' },
    { question: 'What is the eligibility for MHT-CET?', answer: 'Candidates must have passed Class 12 or equivalent with Physics, Chemistry, and Mathematics/Biology as compulsory subjects. There is no minimum aggregate requirement for appearing in MHT-CET. However, for admission to engineering colleges, candidates typically need 45% or above in PCM/PCB. Maharashtra state domicile is not mandatory for appearing — non-Maharashtra candidates can appear but are eligible only for institutional quota seats or minority institutions.' },
    { question: 'How does MHT-CET compare to JEE Main?', answer: 'MHT-CET is specifically for admission to Maharashtra engineering colleges and tests only the Maharashtra Board syllabus, with questions often based directly on HSC textbook problems. JEE Main is a national-level exam covering CBSE/NCERT syllabus and tests conceptual understanding more deeply. A strong JEE Main preparation covers about 60-70% of MHT-CET, but MHT-CET requires additional focus on Maharashtra Board textbooks and HSC-specific problem-solving. The percentile cutoffs for top colleges (COEP, VJTI, ICT) are typically above 99.5 percentile in MHT-CET.' },
  ],
  'ap-eapcet': [
    { question: 'What is AP EAPCET and who should appear?', answer: 'AP EAPCET (Andhra Pradesh Engineering, Agriculture & Pharmacy Common Entrance Test) is a state-level exam conducted by APSCHE (Andhra Pradesh State Council of Higher Education) for admission to undergraduate engineering, agriculture, and pharmacy programmes in colleges across Andhra Pradesh. It is specifically for students who have completed their intermediate education (Class 12) under the BIEAP (Board of Intermediate Education, Andhra Pradesh) or equivalent — students from other state boards are generally not eligible unless they meet specific NRI or category criteria.' },
    { question: 'What is the AP EAPCET exam pattern?', answer: 'AP EAPCET (Engineering) consists of 160 multiple-choice questions: Physics (40 questions), Chemistry (40 questions), and Mathematics (80 questions). Each question carries 1 mark. There is no negative marking. The exam is conducted online (CBT) over 3 hours. The questions are based on the BIEAP Class 12 syllabus. For Agriculture & Pharmacy streams, the pattern differs slightly (Physics, Chemistry, Botany, Zoology). Students from the MPC stream attempt the engineering paper; BiPC stream students attempt the agriculture/pharmacy paper.' },
    { question: 'How is AP EAPCET rank used for engineering admission?', answer: 'AP EAPCET scores are used for the Convener quota (70% of seats in AP engineering colleges) — the remaining 30% falls under the Management Quota. The rank is calculated based on the normalised EAPCET score. Top ranks (under 1,000) can get admission into top colleges like IIIT Sri City, VRS College, or government colleges. For autonomous colleges and top private institutions, a rank within 10,000 is generally competitive. A special integrated counselling process is used for seat allocation across all colleges in Andhra Pradesh. Students also need to meet the 45% aggregate requirement in PCM for eligibility.' },
  ],

  'gujcet': [
    { question: 'What is GUJCET and who is it for?', answer: 'GUJCET (Gujarat Common Entrance Test) is a state-level engineering entrance exam conducted by GSEB (Gujarat Secondary and Higher Secondary Education Board) for admission to B.E./B.Tech programmes in colleges across Gujarat. It is primarily for students who have completed their H.S.C. (Class 12) from the GSEB board — but students from other boards (CBSE, ICSE) are also eligible to appear. GUJCET is typically held in April, and the result is combined with JEE Main scores for the Gujarat admission process.' },
    { question: 'What is the GUJCET exam pattern?', answer: 'GUJCET consists of two papers: Physics-Chemistry (100 questions, 120 minutes) and Mathematics (50 questions, 60 minutes). All questions are multiple-choice with four options. Each correct answer carries 1 mark. There is a negative marking of 0.25 marks per wrong answer. The exam is conducted offline (pen-and-paper) at designated centres across Gujarat. The questions are based on the GSEB Class 12 syllabus.' },
    { question: 'How is GUJCET used for Gujarat engineering admission?', answer: 'Gujarat admissions use a combined merit calculated as: JEE Main percentile (weight 48%) + GUJCET marks (weight 12%) + Class 12 Board marks (weight 40%). This combined score determines the state merit rank for counselling under the Gujarat Admission Professional Bodies. Through this process, students can secure seats in government colleges like LD College of Engineering, government-aided institutions, and private colleges across Gujarat. The top colleges — L.D. College of Engineering, Dharmsinh Desai University, DDIT — typically require a state rank within 1,000.' },
  ],
  'mhcet': [
    { question: 'What is MHCET and who is it for?', answer: 'MHCET (Maharashtra Common Entrance Test) or MAH-MBA/MMS-CET is conducted by the Maharashtra State Cell for admission to MBA/MMS programmes in management colleges across Maharashtra. It is the state-level entrance exam for Maharashtra\'s top B-schools including JBIMS (Jamnalal Bajaj Institute of Management Studies), SIMSREE (Sydenham Institute of Management Studies Research and Entrepreneurship Education), and PUMBA (Pune University Management Business Academy). MHCET is accepted by over 400 MBA colleges in Maharashtra — primarily for Maharashtra domicile candidates, though some seats are available for All India candidates.' },
    { question: 'What is the MHCET exam pattern?', answer: 'MHCET consists of 200 multiple-choice questions to be answered in 150 minutes (2.5 hours). The sections are: Logical Reasoning (75 questions), Abstract Reasoning (25 questions), Quantitative Aptitude (75 questions), and Verbal Ability/Reading Comprehension (25 questions). There is no negative marking in MHCET. The exam is conducted online (CBT) at designated centres across Maharashtra and other states. The difficulty level is generally lower than CAT — most questions are in the easy to moderate range.' },
    { question: 'What score do I need for MHCET?', answer: 'A score of 99+ percentile in MHCET (approximately 145+ out of 200) is needed for the top colleges like JBIMS and SIMSREE. For other top-tier colleges in Mumbai and Pune, a score of 90+ percentile (approximately 120+) is competitive. MHCET percentile is calculated based on the normalised score across all test takers. Unlike CAT, MHCET cutoffs are expressed in percentiles rather than raw scores. Maharashtra domicile candidates get priority in the centralized admission process (CAP) — approximately 70% of seats are reserved for Maharashtra candidates, 30% for All India candidates.' },
  ],
  'nata': [
    { question: 'What is NATA and who is it for?', answer: 'NATA (National Aptitude Test in Architecture) is the national-level entrance exam for admission to B.Arch (Bachelor of Architecture) programmes in India, conducted by the Council of Architecture (COA). It is mandatory for admission to all architecture programmes in India — without a valid NATA score, candidates cannot secure an architecture seat in any Indian institution (government or private). NATA assesses a candidate\'s aptitude for architecture through drawing, observation, and aesthetic sense tests. Candidates who have passed Class 12 with Mathematics as a compulsory subject are eligible. NATA is conducted twice a year (typically March/April and June/July) at designated test centres across India.' },
    { question: 'What is the NATA exam pattern?', answer: 'NATA consists of two parts: Part A — Mathematics & General Aptitude (100 multiple-choice questions, 90 minutes, conducted online at test centres) covering Mathematics (60 questions from Class 11-12), General Aptitude (40 questions covering visual reasoning, logical reasoning, numerical reasoning, verbal reasoning), and English (40 questions). Part B — Drawing Test (02 questions, 90 minutes, conducted offline on A4 paper at designated centres) testing freehand drawing, memory drawing, perspective drawing, and architectural awareness. Each correct answer in Part A carries 2 marks; there is no negative marking. Part B carries 40 marks per question.' },
    { question: 'What score do I need for NATA admission?', answer: 'NATA scores are reported out of 200 (Part A: 200 marks, Part B: 80 marks, scaled to 200). A NATA score of 100+ out of 200 is generally considered passing and sufficient for admission to most architecture colleges. For top architecture schools like School of Planning and Architecture (SPA) Delhi, IIT Roorkee (Architecture), and JJ College of Architecture, a NATA score of 130+ is typically required. For other NATA-accepting private colleges, a score of 80–100 is usually sufficient. The COA sets the minimum qualifying NATA score each year (typically 30% aggregate) but individual colleges set higher cutoffs based on demand.' },
  ],
  'lpunest': [
    { question: 'What is LPUNEST and which programmes does it cover?', answer: 'LPUNEST (Lovely Professional University National Entrance and Scholarship Test) is the entrance and scholarship exam conducted by Lovely Professional University (LPU) in Punjab — one of India\'s largest private universities with over 30,000 students. LPUNEST is used for admission to a wide range of programmes including B.Tech (all branches), MBA, BBA, Law (LLB/BA LLB), Agriculture, Design, Hotel Management, and many more. LPU is unique in that it conducts its own entrance exam — unlike most universities that rely on national or state-level exams. LPUNEST also serves as a scholarship test — the scholarship amount is determined by the LPUNEST score and Class 12 percentage.' },
    { question: 'What is the LPUNEST exam pattern?', answer: 'LPUNEST is an online (CBT) exam with pattern varying by programme: For B.Tech: 90 questions in 150 minutes covering Physics (30), Chemistry (30), Mathematics (30), and English (10 questions). For MBA: 80 questions in 120 minutes covering Verbal Ability & Reading Comprehension, Quantitative Aptitude, and Logical Reasoning. For Law (LPUNEST + CLAT score): similar management aptitude pattern. There is no negative marking in LPUNEST. The exam is conducted at designated centres across India and also has a remote proctored home-based option. Candidates can take LPUNEST from home with a laptop and webcam.' },
    { question: 'What scholarship can I get through LPUNEST?', answer: 'LPU awards scholarships based on LPUNEST scores and previous academic performance: Full scholarship (100% tuition fee waiver) is for students scoring 90%+ percentile in LPUNEST and 90%+ in Class 12. 50% scholarship is for 80–89% percentile in LPUNEST and 80%+ in Class 12. 30% scholarship is for 70–79% percentile in LPUNEST. Scholarships are renewed every semester based on CGPA — a minimum 8.0 SGPA is needed to maintain scholarships above 30%. LPU\'s total fee for B.Tech is approximately ₹2–3 lakhs per semester after scholarship, making it relatively affordable compared to other private universities. Scholarships make LPU accessible to many students who might not afford full fees.' },
  ],
  'jeeupsee': [
    { question: 'What is JEEUPSEE and who is it for?', answer: 'JEEUPSEE (Uttar Pradesh State Entrance Examination) is a state-level engineering entrance exam conducted by AKTU (Dr. A.P.J. Abdul Kalam Technical University) for admission to B.Tech/B.Pharm programmes in colleges across Uttar Pradesh. It is open to candidates who have passed their Class 12 (or equivalent) from a recognised board — UP domicile is required for the majority of seats under the state quota. JEEUPSEE is the primary entrance exam for government and private engineering colleges in Uttar Pradesh, including AKTU itself, and is used for around 800,000+ aspirants each year.' },
    { question: 'What is the JEEUPSEE exam pattern?', answer: 'JEEUPSEE consists of 3 papers: Paper 1 (for B.Tech — Physics, Chemistry, and Mathematics, 75 questions each, 3 hours) and Paper 2 (for B.Arch/B.Pharm — Mathematics, Aptitude Test, and Drawing). All questions are multiple-choice with four options. Each correct answer carries 4 marks; there is a negative marking of 1 mark per wrong answer. The exam is conducted offline (pen-and-paper) in designated centres across Uttar Pradesh and other states. Questions are based on the UP Board Class 12 syllabus.' },
    { question: 'How does JEEUPSEE admission work?', answer: 'JEEUPSEE scores are used for counselling through AKTU\'s centralized admission process. The rank is calculated based on the normalised JEEUPSEE score. Based on rank, candidates participate in online counselling for seat allocation across government colleges (IET Lucknow, MMM Gorakhpur, BIET Jhansi), government-aided, and private self-financing institutions in Uttar Pradesh. IET Lucknow typically requires a rank under 1,000 for popular branches. For other top government colleges, a rank within 5,000 is competitive. Private colleges accept ranks up to 50,000 or more depending on the college and branch.' },
  ],
  'keam': [
    { question: 'What is KEAM and who is it for?', answer: 'KEAM (Kerala Engineering, Agriculture and Medical Entrance Examination) is conducted by the Commissioner of Entrance Examination (CEE), Kerala for admission to B.Tech/B.E. programmes in government and private colleges across Kerala. It is specifically for students who have completed their Class 12 H.S.C. (or equivalent) from a recognised board — there is a mandatory Kerala domicile requirement or NRI category for non-domiciled students. KEAM tests Physics, Chemistry, and Mathematics at the Class 11 and 12 level for engineering admissions.' },
    { question: 'What is the KEAM exam pattern?', answer: 'KEAM consists of two papers: Paper 1 (Physics & Chemistry, 120 questions, 150 minutes) and Paper 2 (Mathematics, 120 questions, 150 minutes). All questions are objective MCQs. Each correct answer carries 4 marks in Physics and Chemistry, and 4 marks per correct answer in Mathematics. There is a negative marking of 1 mark per wrong answer. The exam is conducted online (CBT) at designated centres. KEAM is separate from JEE Main — students can appear for both exams and use either score for Kerala engineering admissions.' },
    { question: 'How does KEAM admission work?', answer: 'KEAM scores are used for the centralised admission process (CAP) in Kerala. The rank list is prepared based on the KEAM score (50% weight) plus marks in Physics and Chemistry in the Class 12 Board exam (50% weight). The combined score determines the merit rank for seat allocation across government, aided, and private self-financing colleges in Kerala. Top colleges like College of Engineering Trivandrum (CET), Government Engineering College Thrissur, and Model Engineering College typically require a rank within 2,000 for general category. NRI candidates have a separate quota with different cutoffs.' },
  ],
  'kcet': [
    { question: 'What is KCET and who is it for?', answer: 'KCET (Karnataka Common Entrance Test) is conducted by the Karnataka Examination Authority (KEA) for admission to B.Tech, B.Pharm, B.Arch, and other professional degree programmes in government, aided, and private colleges across Karnataka. It is open to students who have completed their Class 12 (2nd PUC) from a recognised board in Karnataka — students from outside Karnataka are also eligible but compete under the General category (non-Karnataka) for a limited number of seats. KCET tests Physics, Chemistry, and Mathematics/Biology at the Class 11 and 12 level. It is the gateway to some of Karnataka\'s best engineering colleges including RV College of Engineering, PES University, and BMS College of Engineering.' },
    { question: 'What is the KCET exam pattern?', answer: 'KCET consists of 3 papers of 60 questions each (180 minutes per paper): Paper 1 — Physics (60 questions, 60 marks), Paper 2 — Chemistry (60 questions, 60 marks), and Paper 3 — Mathematics OR Biology (60 questions, 60 marks, candidate\'s choice based on their stream). Each question carries 1 mark with no negative marking. The exam is conducted offline (pen-and-paper) over 2 days at designated centres in Karnataka. Candidates appearing for Medical (NEET) can take Biology in Paper 3 for B.Pharm or para-medical courses. The KCET marks are considered along with 50% weight given to Class 12 PCM/PCB marks for the final merit ranking.' },
    { question: 'How does KCET admission and ranking work?', answer: 'KCET admission is based on the combined merit score: 50% KCET exam marks + 50% Class 12 PCM/PCB marks (for relevant streams). Separate rank lists are prepared for different categories (GM, 2A, 2B, 3A, 3B, SC, ST, etc.). For government college seats (70% of total), Karnataka domicile students compete within their category. For private college seats (30% management quota), Karnataka students have access to 85% of management quota seats. Top colleges like RVCE (Computer Science) typically require a rank within 500 for GM category; BMSCE (CS) requires rank within 1,000. Other top options include UVCE Bangalore, PES University, and MIT Manipal.' },
  ],
  'buet-adm': [
    { question: 'What is BUET and how does its admission work?', answer: 'BUET (Bangladesh University of Engineering and Technology) is Bangladesh\'s premier and most prestigious engineering university, consistently ranked #1 in Bangladesh for engineering education. BUET admits students through a centralised university admission test conducted annually after HSC. Students from the Science background in HSC (or equivalent) are eligible. BUET offers undergraduate programmes in Civil, Electrical, Mechanical, Computer Science, Architecture, and several other engineering disciplines. BUET is highly competitive — approximately 100,000+ students appear for the BUET admission test each year, competing for around 1,500 seats.' },
    { question: 'What is the BUET admission test pattern?', answer: 'The BUET admission test consists of 100 multiple-choice questions to be answered in 3 hours. The questions come from three subjects: Physics (approximately 35 questions), Chemistry (approximately 35 questions), and Mathematics (approximately 30 questions) — all covering the HSC/equivalent syllabus. Each wrong answer carries negative marking (-0.25 per wrong answer). The total marks for the exam vary by year but typically range between 100–120. The exam is conducted in a single sitting on the same day across BUET\'s campus in Dhaka. After the written test, a separate viva voce may be conducted for Architecture applicants.' },
    { question: 'What rank do I need for BUET admission?', answer: 'To get into BUET through the general merit list, you typically need to be in the top 1,000 ranks out of 100,000+ applicants. For the most popular departments (Computer Science & Engineering, Electrical & Electronic Engineering), you generally need a rank within the top 100–200. BUET uses a weighted aggregate score based on: SSC/HSC GPA (or equivalent, worth significant weight) + the BUET admission test score. A combined rank is then prepared and used for department allocation during counselling. Students from all over Bangladesh compete — domicile does not provide an advantage.' },
  ],
  'wbjee': [
    { question: 'What is WBJEE and who is it for?', answer: 'WBJEE (West Bengal Joint Entrance Examination) is a state-level engineering entrance exam conducted by the West Bengal Joint Entrance Examinations Board (WBJEEB) for admission to undergraduate engineering, pharmacy, and architecture programmes in colleges across West Bengal. It is open to students who have completed their Class 12 from any recognised board (WBCHSE, CBSE, ICSE) — West Bengal domicile is preferred for government college seats but not mandatory. WBJEE is the primary entrance exam for institutions like Jadavpur University, IIEST Shibpur, and all government and private engineering colleges in West Bengal.' },
    { question: 'What is the WBJEE exam pattern?', answer: 'WBJEE consists of three papers: Paper 1 (Mathematics, 75 questions, 2 hours), Paper 2 (Physics & Chemistry combined, 100 questions, 2 hours). All questions are multiple-choice with four options. There are three categories of questions: Category 1 (single correct answer, 1 mark each), Category 2 (single correct answer, 2 marks each), and Category 3 (multiple correct answers, 2 marks each — must identify all correct options). There is no negative marking in WBJEE. The exam is conducted offline (pen-and-paper) in designated centres across West Bengal and other states.' },
    { question: 'How does WBJEE admission work?', answer: 'WBJEE scores are used for the centralised counselling process (WEBCOUNS) in West Bengal. The merit rank is based on the normalised WBJEE score. Jadavpur University (the most prestigious) typically requires a rank under 1,000 for popular branches like Computer Science, Electronics, and Electrical Engineering. For government colleges like IIEST Shibpur, KGEC, and JIS College of Engineering, a rank within 5,000 is generally competitive. Private aided and self-financing colleges accept ranks up to 30,000 or more. The counselling process includes multiple rounds with fresh rank lists after each round.' },
  ],
  'acsee': [
    { question: 'What is ACSEE and who is it for?', answer: 'ACSEE (Advanced Certificate of Secondary Education Examination) is Tanzania\'s upper-secondary school leaving examination taken after completing Form 6 (two years after Form 4 NTSC). It is the equivalent of A-Levels or the Kenyan KCSE. Students who have completed their CSEE (Form 4) and want to pursue higher education in Tanzania must pass ACSEE to qualify for university admission. ACSEE is administered by the National Examinations Council of Tanzania (NECTA). It covers Arts, Science, and Commercial streams, each with specialised subject combinations required for different university programmes.' },
    { question: 'What are the ACSEE streams and subjects?', answer: 'ACSEE has three main streams: (1) Science — Physics, Chemistry, Mathematics, Biology, Geography, English; (2) Arts — History, Geography, Kiswahili, English, Economics,Commerce; (3) Commerce — Economics, Commerce, Accounting, Mathematics, Geography, English. Each student selects a combination of at least 3 principal passes (subsidiary passes are also awarded). For direct university admission, students need at least 2 principal passes in relevant subjects for their chosen programme. Medical programmes typically require 3 principal passes in Science subjects including Chemistry and Biology.' },
    { question: 'How are ACSEE results used for university admission in Tanzania?', answer: 'Tanzanian universities use ACSEE results through the TAMISEMI admission system (for public universities) and through individual university direct admissions. The minimum requirement is usually 2 principal passes (grade A–D) in relevant subjects. For competitive courses like Medicine, Engineering, and Law, 3 principal passes with good grades are typically required. Students also need a minimum pass in Kiswahili and English at subsidiary level. After ACSEE results are released (typically in May), students apply through the university admission portal and are placed based on their exam performance and subject combinations.' },
  ],
  'nda': [
    { question: 'What is the eligibility for NDA?', answer: 'Candidates must have completed Class 12 (or be appearing) with Physics, Chemistry, and Mathematics for the IMA/INA/Air Force wings. For the Naval Academy, Engineering branch is mandatory. Candidates must be between 16.5 and 19.5 years of age as of the first day of the month in which the course begins. Only unmarried male and female candidates are eligible. Citizenship: Indian citizens only.' },
    { question: 'What is the NDA exam pattern?', answer: 'NDA consists of two written papers: Paper 1 (Mathematics, 300 marks, 2.5 hours) covering Algebra, Matrices, Trigonometry, Analytical Geometry, Differential Calculus, Integral Calculus, Differential Equations, Vector Algebra, Probability, Statistics; and Paper 2 (General Ability Test, 600 marks, 2.5 hours) divided into English (200 marks) and General Knowledge (400 marks) covering Physics, Chemistry, History, Geography, and Current Affairs. Both papers are objective MCQs. The exam is conducted twice a year (NDA I and NDA II) by UPSC.' },
    { question: 'What does the NDA SSB interview involve?', answer: 'The Services Selection Board (SSB) interview is a 5-day procedure split into two stages: Stage I (Day 1 — Officer Intelligence Rating and Picture Perception) and Stage II (Days 2-5 — Psychology Tests, Group Testing Officer tasks, Personal Interview, and Conference). Candidates are assessed on officer-like qualities: Leadership, Diligence, Cooperation, Endurance, and Initiative. The SSB interview carries 900 marks combined with the written exam for the final merit list.' },
  ],
  'legon-adm': [
    { question: 'What is Legon ADM and how does university admission work in Ghana?', answer: 'Legon ADM (Admissions Test) refers to the University of Ghana (UG) admissions process for undergraduate programmes at Legon, Accra — Ghana\'s premier university. The University of Ghana uses a combination of West African Senior School Certificate Examination (WASSCE) results and the Legon ADM test for certain programmes. The Legon ADM test is typically required for competitive programmes where WASSCE alone is insufficient for selection. The test is conducted by the University of Ghana\'s IT Services and admissions office. For most programmes, applicants need 6 credits (A1–C6) in their WASSCE including English Language, and additional programme-specific requirements.' },
    { question: 'What programmes require the Legon ADM test?', answer: 'The Legon ADM test is required for the most competitive programmes at the University of Ghana including: Law (LLB), Medicine and Surgery (MBChB), Engineering (BSc Engineering), Business Administration (BBA), and Architecture. For these programmes, a strong WASSCE result alone is not sufficient — candidates must also pass the university\'s own admissions test. The test content varies by programme: Law requires an entrance test in Legal Reasoning and English; Medicine may require an interview; Engineering requires Mathematics and Science reasoning tests. Candidates should check the University of Ghana admissions portal for the specific test format for their programme.' },
    { question: 'How can international students apply to University of Ghana Legon?', answer: 'International students (non-Ghanaian WASSCE holders) apply to the University of Ghana through the same admissions portal as Ghanaian students but may have a separate admissions process. Applicants with foreign qualifications (e.g., GCSE/IGCSE, American High School Diploma, IB) must have their certificates evaluated by the Ghana Education Trust Fund (GETFund) or the National Accreditation Board. International students also need to demonstrate English language proficiency. For Medicine, Law, and other competitive programmes, the Legon ADM test or interview is also required. The University of Ghana has dedicated international student support through the Office of International Education.' },
  ],
  'mu-oet': [
    { question: 'What is MU-OET and which programmes does it cover?', answer: 'MU-OET (Manipal University Online Entrance Test) is the umbrella entrance exam for Manipal Academy of Higher Education (MAHE), which includes Manipal University in Karnataka and its campuses in Jaipur, Dubai, and other locations. MU-OET is used for admission to a wide range of programmes including B.Tech (all branches), MBBS (through NEET, not MU-OET), BDS, B.Pharm, M.Tech, MBA, and other postgraduate programmes. Manipal is one of India\'s largest private universities with a strong reputation in engineering, medicine, and management education. MU-OET is typically conducted online between February and May each year.' },
    { question: 'What is the MU-OET exam pattern for B.Tech?', answer: 'MU-OET for B.Tech consists of 200 multiple-choice questions to be answered in 2 hours 30 minutes. The sections are: Physics (50 questions), Chemistry (50 questions), Mathematics (100 questions). Each correct answer carries 1 mark. There is no negative marking in MU-OET. The exam is conducted online (CBT) at designated test centres and can also be taken from home (online proctored mode) in some years. Questions are based on the CBSE Class 11-12 syllabus. Candidates who have appeared for JEE Main or have a good JEE score may get direct shortlisting for Manipal\'s B.Tech programmes.' },
    { question: 'How does Manipal B.Tech admission work and what score do I need?', answer: 'Manipal B.Tech admission uses MU-OET score for the initial shortlisting, but candidates can also apply with JEE Main scores. A MU-OET score of 140+ out of 200 is generally competitive for popular branches like Computer Science, Information Technology, and Electronics at Manipal\'s main campus (Karnataka). For the Jaipur campus, cutoffs are slightly lower. The Manipal counselling process (MU-OET counselling) allocates seats based on score and preference. The tuition fees for B.Tech at Manipal is approximately ₹3–4 lakhs per year — significantly higher than government engineering colleges but lower than some private peers. Manipal also offers scholarship seats based on MU-OET rank.' },
  ],
  'met': [
    { question: 'What is MET and how does it differ from MU-OET?', answer: 'MET (Manipal Entrance Test) is Manipal Academy of Higher Education\'s entrance test for postgraduate programmes — specifically MBA and M.Tech. Unlike MU-OET which covers undergraduate programmes (B.Tech, B.Pharm), MET is specifically for students who already have a bachelor\'s degree and want to pursue a Master\'s. MET is accepted for MBA (all specialisations) and M.Tech programmes across Manipal\'s Karnataka, Jaipur, and Dubai campuses. Both MET and MU-OET are conducted by Manipal Academy but serve different academic levels — MET is the postgraduate entrance, MU-OET is undergraduate.' },
    { question: 'What is the MET exam pattern?', answer: 'MET for MBA consists of 120 multiple-choice questions to be answered in 2 hours 30 minutes. The sections are: Quantitative Aptitude (30 questions), Data Interpretation & Logical Reasoning (30 questions), English Language (30 questions), and General Awareness (30 questions). MET for M.Tech has questions related to the candidate\'s undergraduate engineering stream (subject-specific). There is no negative marking in MET. The exam is conducted online (CBT) at designated centres across India. MET is typically held in April-May each year, with results announced in May-June.' },
    { question: 'What MET score do I need for Manipal MBA?', answer: 'A MET score of 120+ out of 160 is generally competitive for the Manipal MBA programme at the main Karnataka campus. For the top MBA specialisations (Finance, Business Analytics), a score of 130+ is preferred. Manipal accepts MET scores for its MBA programmes which are ranked among the top 30 B-schools in India. The Manipal MBA fees are approximately ₹5–8 lakhs per year depending on specialisation and campus. MET scores are accepted for the Manipal selection process which includes group discussion (GD) and personal interview (PI) rounds after the written test.' },
  ],
  'viteee': [
    { question: 'What is VITEEE and which programmes does it cover?', answer: 'VITEEE (Vellore Institute of Technology Engineering Entrance Examination) is the entrance exam for VIT Vellore — consistently ranked among India\'s top private engineering universities. VITEEE is for admission to B.Tech programmes at VIT Vellore (Tamil Nadu), VIT Chennai, VIT-AP (Andhra Pradesh), and VIT-Bhopal campuses. VIT is one of India\'s most sought-after private engineering institutions with over 20,000 B.Tech seats across all campuses. VITEEE is conducted annually (typically April) and is a computer-based test (CBT) held across 200+ cities in India and abroad (Dubai, Kuwait, Qatar, Oman).' },
    { question: 'What is the VITEEE exam pattern?', answer: 'VITEEE consists of 125 multiple-choice questions to be answered in 2 hours 30 minutes. The sections are: Physics (40 questions), Chemistry (40 questions), Mathematics/Biology (45 questions — candidates choose either), and English (10 questions — grammar, vocabulary). Each correct answer carries 1 mark with no negative marking. The exam is conducted online (CBT) at designated test centres. The syllabus is based on CBSE Class 11-12 Physics, Chemistry, and Mathematics/Biology. VIT also accepts JEE Main scores for VITEEE counselling — candidates with JEE Main rank below 50,000 can directly appear for VIT counselling without taking VITEEE.' },
    { question: 'What rank/cutoff do I need for VITEEE?', answer: 'For VIT Vellore (main campus) Computer Science and Electronics Engineering: a VITEEE rank within 5,000 is competitive. For other top branches (IT, Mechanical, Electrical): rank within 10,000. For VIT Chennai: rank within 10,000 for CS. For VIT-AP and VIT-Bhopal: cutoffs are lower, rank within 20,000 for CS. VIT counselling allocates seats based on rank — higher rank = earlier counselling slot = better chance of getting preferred branch and campus. Over 2 lakh candidates appear for VITEEE each year for approximately 5,000 seats at VIT Vellore alone, making it highly competitive.' },
  ],
  'neet-pg': [
    { question: 'What is NEET PG and who is it for?', answer: 'NEET PG (National Eligibility cum Entrance Test for Postgraduate) is a national-level entrance exam conducted by the National Board of Examinations (NBE) for admission to MD (Doctor of Medicine), MS (Master of Surgery), and PG Diploma courses in government and private medical colleges across India. It is the single mandatory exam for all medical graduates seeking postgraduate admission in India, having replaced individual state-level PG exams and the All India PG Medical Exam from 2017 onwards.' },
    { question: 'What is the NEET PG exam pattern?', answer: 'NEET PG consists of 200 multiple-choice questions to be answered in 3 hours and 30 minutes (210 minutes) on a computer. The questions cover all 19 subjects from the MBBS curriculum divided into three parts: Part A (Anatomy, Physiology, Biochemistry — 50 questions each), Part B (Pathology, Pharmacology, Microbiology, Forensic Medicine — 50 questions each), and Part C (Medicine, Surgery, Obstetrics & Gynecology, Pediatrics — 100 questions). Each correct answer carries 4 marks; 1 mark is deducted for each wrong answer. The pass mark is 50% (300 out of 800).' },
    { question: 'What is the eligibility for NEET PG?', answer: 'Candidates must have an MBBS degree (or provisional MBBS pass certificate) from an NMC-recognized medical college, and must have completed or be completing their compulsory rotatory internship by the time of admission. There is no upper age limit for NEET PG (the previous cap of 34 years was struck down by the Supreme Court in 2022). Foreign medical graduates with an FMGE pass certificate are also eligible to appear for NEET PG. Candidates must be registered with the State Medical Council or NMC.' },
  ],
  'sbi-clerk': [
    { question: 'What is SBI Clerk and what does it lead to?', answer: 'SBI Clerk (Junior Associates) is a clerical-level recruitment exam conducted by the State Bank of India for appointment as a Clerk (Junior Associate) in SBI branches across India. It is one of the most sought-after banking exams in India due to SBI\'s reputation as the largest public sector bank. Selected candidates are appointed as Junior Associates and can grow to higher positions like Probationary Officer (through internal exams) over time. The exam is conducted annually by SBI through its official website.' },
    { question: 'What is the SBI Clerk exam pattern?', answer: 'SBI Clerk exam has two stages: Preliminary (Phase 1) and Main (Phase 2). The Preliminary exam has 100 questions (English Language: 30, Numerical Ability: 35, Reasoning Ability: 35) to be completed in 1 hour. The Main exam has 190 questions (General/Financial Awareness: 50, General English: 40, Quantitative Aptitude: 50, Reasoning Ability & Computer Aptitude: 50) to be completed in 2 hours 40 minutes. There is no negative marking in the Preliminary exam; the Main exam has 0.25 marks deducted for wrong answers.' },
    { question: 'What is the salary and career progression for SBI Clerks?', answer: 'SBI Clerks (Junior Associates) receive a starting basic pay of ₹19,900 (in ₹19,900–1,380–45,490–500–1,640–54,630–1,910–63,280) plus allowances (Dearness Allowance, House Rent Allowance, Transport Allowance, etc.), totaling approximately ₹29,000–₹35,000 per month in hand depending on the city. After 3 years of service, clerks can appear for the Internal Promotion Exam to become a Probationary Officer (PS Scale-I), and further promotions lead to Middle Management Scale (MMS) and Senior Management Scale positions.' },
  ],
  'sbi-po': [
    { question: 'What is SBI PO and how does admission work?', answer: 'SBI PO (Probationary Officer) is a prestigious recruitment exam conducted by the State Bank of India for appointment as Probationary Officers (Assistant Manager) in SBI branches across India. SBI PO is considered one of the most sought-after banking jobs in India due to the attractive salary, allowances, and rapid career progression. After selection, POs undergo a probation period of 2 years during which they receive structured training across various banking operations. The exam is conducted annually by SBI through its official website sbi.co.in.' },
    { question: 'What is the SBI PO exam pattern?', answer: 'SBI PO has three stages: Preliminary (Phase 1), Main (Phase 2), and Interview/Group Discussion (Phase 3). The Preliminary exam has 100 questions (English Language: 30, Numerical Ability: 35, Reasoning Ability: 35) to be completed in 1 hour. The Main exam has 200 questions in four sections: Reasoning & Computer Aptitude (45 questions), Data Analysis & Interpretation (35), General/Economy/Banking Awareness (40), and English Language (35), plus a Descriptive Test (Letter Writing & Essay) of 50 marks. The final merit list is based on Main marks + Interview marks (weightage: 75:25).' },
    { question: 'What is the SBI PO salary and growth path?', answer: 'SBI PO receives a starting basic pay of ₹41,960 (in ₹41,960–1,340–51,670–1,460–62,330–1,840–73,870–2,050–85,580) plus allowances (DA, HRA, Transport Allowance, etc.), totaling approximately ₹58,000–₹65,000 per month in hand at metro centres. After probation, POs are confirmed as Assistant Managers (Scale-I). Career progression: PO → Assistant Manager → Branch Manager → Deputy Manager → Chief Manager → Assistant General Manager → Deputy General Manager → General Manager. Top performers can reach the level of Chairman/Managing Director.' },
  ],
  'mht-cet-law': [
    { question: 'What is MH CET Law and who accepts it?', answer: 'MH CET Law (Maharashtra Common Entrance Test for Law) is a state-level entrance exam conducted by the State Common Entrance Test Cell, Maharashtra for admission to 3-year LLB and 5-year BA LLB programmes in participating colleges across Maharashtra. It is accepted by all government and aided law colleges in Maharashtra including GLC Mumbai (Government Law College, Mumbai), ILS Pune (Indian Law Society), and MNLU Mumbai (Maharashtra National Law University). For 3-year LLB seats, any graduate is eligible; for 5-year BA LLB, Class 12 students are eligible.' },
    { question: 'What is the MH CET Law exam pattern?', answer: 'MH CET Law for 3-year LLB has 120 multiple-choice questions to be completed in 2 hours (120 minutes). The sections are: Legal Aptitude (40 questions), GK & Current Affairs (30 questions), Logical Reasoning (30 questions), and English (20 questions). Each correct answer carries 1 mark; there is no negative marking. For 5-year BA LLB, the exam has 150 questions in the same proportion covering Legal Aptitude, GK & Current Affairs, Logical Reasoning, English, and Elementary Mathematics. The exam is conducted online (CBT) once a year.' },
    { question: 'How does MH CET Law counselling work?', answer: 'MH CET Law counselling is conducted by the State CET Cell in multiple rounds. Candidates fill their college and course preferences online after the result is declared. Seat allocation is based on MH CET Law rank, category (GMC, OBC, SC, ST, SBC, VJNT, EWS, NTB, NTC, NTD), and preference choices. For 3-year LLB, the CAP (Centralized Admission Process) rounds allocate seats in government colleges, autonomous colleges, and unaided minority colleges. Candidates must verify their documents at designated facilitation centres after each round of allocation.' },
  ],
  'up-psc': [
    { question: 'What is UPPSC and how does it differ from UPSC?', answer: 'UPPSC (Uttar Pradesh Public Service Commission) is the state-level civil services exam for the state of Uttar Pradesh, conducted separately from UPSC (which recruits for All-India Services). UPPSC recruits for Uttar Pradesh Administrative Service (APS), Provincial Civil Service (PCS), Deputy Collector, Superintendent of Police, and other state-level Group A and B posts. While the exam pattern is similar to UPSC (Prelims, Mains, Interview), the competition is specific to Uttar Pradesh and covers state-specific topics like UP-specific history, geography, and culture in the Mains exam.' },
    { question: 'What is the UPPSC exam pattern?', answer: 'UPPSC Prelims consists of two papers: General Studies Paper I (200 marks, 200 questions on History, Geography, Polity, Economy, Science, Environment, and Current Affairs) and General Studies Paper II (200 marks, 200 questions on Reasoning, Decision Making, Mathematics, and English/Hindi comprehension) — popularly called CSAT. Only those who qualify Prelims appear for Mains, which has 7 conventional papers: Hindi, Hindi Essay, General Studies I (Indian History, World History, Geography), General Studies II (Polity, Governance, Social Justice), General Studies III (Economy, Science, Technology), General Studies IV (Ethics, Integrity, Aptitude), and an Optional Subject Paper. The Interview is 100 marks.' },
    { question: 'What posts does UPPSC recruit for?', answer: 'UPPSC recruits for approximately 400+ posts per year including: Provincial Civil Service (PCS) — District Magistrate, Block Development Officer, City Deputy Superintendent of Police; Uttar Pradesh Administrative Service (APS) — faster career progression within the UP state bureaucracy; Food & Civil Supplies Officer, Labour Commissioner, Transport Commissioner, and various other Group A and B posts. Selected candidates are appointed as probationers and trained at the Uttar Pradesh Academy of Administration in Lucknow.' },
  ],
  'jupeb': [
    { question: 'What is JUPEB and how does it work?', answer: 'JUPEB (Joint Universities Preliminary Examinations Board) is a Nigerian examination body that conducts the JUPEB programme — a 1-year intensive pre-university programme that prepares students for university admission. JUPEB is accepted as an alternative to JAMB for direct entry admission into Nigerian universities (200+ universities accept JUPEB results). Students choose three subject combinations from Arts, Sciences, or Commercial subjects and study them at a JUPEB accredited centre for one academic year. After passing the JUPEB examinations, students gain direct entry (200 level) into Nigerian universities, skipping the first year.' },
    { question: 'What are the JUPEB subject combinations?', answer: 'JUPEB candidates choose a three-subject combination relevant to their intended university programme. Popular combinations include: Sciences (Physics/Chemistry/Mathematics, Physics/Chemistry/Biology, Chemistry/Biology/Mathematics), Commercial (Economics/Government/Accounting, Economics/Government/Mathematics, Commerce/Accounting/Economics), and Arts (Government/History/Literature, Government/Economics/Literature). The choice of combination determines which university courses a student is eligible for. Students must verify their combination is accepted by their target university and intended course of study before enrolling in a JUPEB programme.' },
  ],
  'nce-cours': [
    { question: 'What is NCE and which Nigerian institutions accept it?', answer: 'NCE (Nigeria Certificate in Education) is a 3-year teacher training programme awarded by Colleges of Education in Nigeria. While NCE is primarily a teaching qualification, holders can use it for direct entry admission into university education programmes (e.g., B.A. Education, B.Sc. Education) where NCE is accepted as satisfying the 100-level entry requirement. NCE is awarded by over 100 accredited Colleges of Education across Nigeria and is regulated by the National Commission for Colleges of Education (NCCE). The NCE qualifying examination is conducted by the exam offices of individual Colleges of Education.' },
  ],
  'putme': [
    { question: 'What is PUTME and how does it work?', answer: 'PUTME (Post-UTME Screening Examination) is the screening examination conducted by individual state universities in Nigeria after JAMB. After scoring in JAMB, candidates who meet the cut-off mark for their chosen university must sit the university\'s PUTME to be considered for admission. Each state university sets its own PUTME exam pattern, date, and cutoff. Unlike JAMB which is national, PUTME is university-specific — candidates must apply to each university\'s PUTME separately after receiving their JAMB results. Polytechnics and colleges of education may have their own post-UTME equivalent.' },
  ],
  'toafa': [
    { question: 'What is TOAFA and which universities accept it?', answer: 'TOAFA (Test of Academic Fitness Award) is an examination conducted by Nigerian universities as part of their screening process for admission, particularly for candidates seeking direct entry or supplementary admission. TOAFA is used by some universities as an alternative or complement to JAMB and post-UTME scores when evaluating candidates. It tests general academic readiness, reasoning ability, and subject-specific knowledge at the secondary school level. The specific pattern and syllabus vary by university. Candidates should check their target university\'s admission handbook for whether TOAFA is accepted for their intended programme.' },
  ],
  'kpkpse': [
    { question: 'What is KP KPSTF and how does it work?', answer: 'The Khyber Pakhtunkhwa (KPK) Public Service Commission conducts the KP KPSTF (Khyber Pakhtunkhwa School Teaching Service) examination for recruitment of Secondary School Teachers (SST) in government schools across Khyber Pakhtunkhwa province, Pakistan. Candidates with a Bachelor\'s or Master\'s degree in the relevant subject plus a Bachelor of Education (B.Ed.) or Teaching Certificate are eligible to appear. The exam consists of written tests in the subject specialization, pedagogy, and general knowledge, followed by an interview for shortlisted candidates.' },
  ],
  'nabe': [
    { question: 'What is NABE and how does it relate to Pakistani education?', answer: 'NABE (National Association for Business Education) in Pakistan refers to the accreditation body and examination framework for business education programmes at higher education institutions. NABE-conducted examinations and certifications are recognized by business schools and corporate employers across Pakistan as demonstrating competency in areas like accounting, management, and business communication. For students, NABE certifications can supplement university degrees to improve employability in finance, banking, and corporate sectors.' },
  ],
  'nlt': [
    { question: 'What is NLT and how is it used?', answer: 'NLT (National Level Test) is a standardized testing framework used by various Indian and international institutions for screening candidates in specific domains. In the Pakistani context, NLT may refer to the National Level Test for Engineering or Business programmes conducted by various testing bodies as part of their admission process. Candidates should check the specific board or institution using the NLT designation to understand the exact pattern, syllabus, and relevance to their intended programme of study.' },
  ],
  'sppsc': [
    { question: 'What is SPPSC and how does it work?', answer: 'SPPSC (Sindh Public Service Commission) is the provincial recruitment body for Sindh province, Pakistan, responsible for recruiting civil servants for various Group A, B, C, and D posts in the Sindh government. Similar to FPSC at the federal level, SPPSC conducts written examinations, interviews, and merit-based selection for posts in Sindh\'s administrative, police, revenue, and other government departments. Candidates must be domiciled in Sindh to apply for most SPPSC posts. The Commission advertises vacancies periodically on its official website sppsc.sindh.gov.pk.' },
  ],
  'mcat': [
    { question: 'What is MCAT and how does it differ from MDCAT?', answer: 'MCAT (Medical College Admission Test) is the standardized entrance exam used in the United States and Canada for admission to medical schools. Unlike MDCAT (Pakistan\'s Medical and Dental Colleges Admission Test) which is Pakistan-specific, MCAT is accepted by medical schools across North America. The exam covers four sections: Biological and Biochemical Foundations, Chemical and Physical Foundations, Psychological, Social, and Biological Foundations, and Critical Analysis and Reasoning Skills. International students (including Pakistanis) planning to study medicine in the USA or Canada must take MCAT and score competitively (510+ for top schools) along with demonstrating research experience and extracurricular involvement.' },
  ],
  'ppsc': [
    { question: 'What is PPSC and how does it work?', answer: 'PPSC (Punjab Public Service Commission) is the provincial recruitment body for Punjab province, Pakistan, responsible for recruiting civil servants for various Group A, B, C, and D posts in the Punjab government. PPSC conducts written competitive examinations, interviews, and merit-based selection for posts including Administrative Service, Police Service, and various other provincial government positions. Candidates must be Punjab domicile holders. The PPSC annual recruitment calendar includes examinations for Multiple Provincial Services (MPS) and Departmental Competitive Examinations. Results and merit lists are published on the PPSC website ppsc.gop.pk after each examination cycle.' },
  ],
  'ts-eamcet': [
    { question: 'What is TS-EAMCET and who is it for?', answer: 'TS-EAMCET (Telangana State Engineering, Agriculture and Medical Common Entrance Test) is conducted by the Telangana State Council of Higher Education (TSCHE) for admission to undergraduate professional programmes in Telangana state. It is a mandatory exam for admission to B.Tech, B.Pharm, B.Sc (Agriculture), and other professional courses in government and private colleges across Telangana. TS-EAMCET is specifically for students who have completed their Intermediate (Class 12) education in Telangana or Andhra Pradesh — it is the Telangana state-level equivalent of AP-EAMCET, with which it was combined before Telangana\'s formation in 2014. Only students belonging to Telangana are eligible for the convenor quota (70% of seats); the remaining 30% falls under management quota.' },
    { question: 'What is the TS-EAMCET exam pattern?', answer: 'TS-EAMCET consists of 160 multiple-choice questions to be answered in 3 hours (180 minutes). The exam is conducted separately for two streams: Engineering (E) stream: Physics (40 questions), Chemistry (40 questions), Mathematics (80 questions). Agriculture & Medical (AM) stream: Physics (40 questions), Chemistry (40 questions), Botany (40 questions), Zoology (40 questions). Each correct answer carries 1 mark; there is no negative marking. The exam is conducted online (CBT) at designated centres in Telangana and Andhra Pradesh. The syllabus is based on the Telangana Board Class 11-12 curriculum.' },
    { question: 'How does TS-EAMCET counselling and admission work?', answer: 'TS-EAMCET scores are processed through a centralised counselling called TS-Counselling (convenor seat allocation). The rank list is prepared based on the TS-EAMCET score. Seats are allocated in three categories: Convenor Quota (70% of seats) — only for Telangana students, allocated based on rank and preferences. Management Quota (30%) — open to all eligible candidates. College-wise Spot Admissions fill remaining vacant seats after regular counselling. Top colleges through TS-EAMCET include: JNTU Hyderabad (best government college), Osmania University College of Engineering, University College of Engineering (Autonomous), and VNR Vignana Jyothi Institute of Engineering. For Computer Science at JNTU Hyderabad, a rank within 1,000 (GM category) is typically required.' },
  ],
  'ap-eamcet': [
    { question: 'What is AP-EAMCET and how does it differ from TS-EAMCET?', answer: 'AP-EAMCET (Andhra Pradesh Engineering, Agriculture and Medical Common Entrance Test) is the state-level entrance exam for admission to professional undergraduate programmes in Andhra Pradesh, conducted by APSCHE (Andhra Pradesh State Council of Higher Education). After Telangana was formed in 2014, Andhra Pradesh and Telangana started conducting separate EAMCET exams — AP-EAMCET for AP students and TS-EAMCET for Telangana students. AP-EAMCET is for students who have completed their Intermediate (Class 12) from the Andhra Pradesh Board of Intermediate Education (BIEAP). It covers admission to B.Tech, B.Pharm, B.Sc (Agriculture), and medical programmes in AP government and private colleges.' },
    { question: 'What is the AP-EAMCET exam pattern?', answer: 'AP-EAMCET consists of 160 multiple-choice questions to be answered in 3 hours. The Engineering stream covers: Physics (40 questions), Chemistry (40 questions), and Mathematics (80 questions) — same structure as TS-EAMCET. The Agriculture & Medical stream covers Physics (40), Chemistry (40), Botany (40), and Zoology (40). Each correct answer carries 1 mark; there is no negative marking. The exam is conducted online (CBT) at designated centres in Andhra Pradesh and also in Hyderabad, Bangalore, and Delhi. The syllabus is based on the BIEAP Class 11-12 curriculum. AP-EAMCET is typically held in May each year.' },
    { question: 'What rank do I need for AP-EAMCET admission?', answer: 'For admission to top colleges through AP-EAMCET: JNTU Kakinada (best government college for engineering in AP) typically requires a rank within 3,000 for Computer Science in the Convener quota. For other top government colleges like VSR College of Engineering and AU College of Engineering (Visakhapatnam), a rank within 10,000 is competitive. For private top colleges like VR Siddhartha College of Engineering and GVP College of Engineering, a rank within 20,000 is sufficient. The Convener quota (70% of seats) is for AP-local students only; the Management quota (30%) is open to all eligible candidates including NRI candidates. APICET covers MBA/MCA admissions separately.' },
  ],
  'gat': [
    { question: 'What is GAT and who should take it?', answer: 'GAT (Graduate Assessment Test) is a standardised aptitude test conducted in Pakistan for admission to postgraduate and professional degree programmes at universities and professional institutions. It assesses a candidate\'s verbal reasoning, quantitative reasoning, and analytical writing skills. GAT is accepted by all universities in Pakistan for admission to MS, MPhil, and postgraduate programmes. It is administered by NTS (National Testing Service) Pakistan and conducted multiple times a year. GAT is essentially Pakistan\'s equivalent of the GRE — a general aptitude test for postgraduate admissions.' },
    { question: 'What is the GAT exam pattern?', answer: 'GAT consists of 100 multiple-choice questions to be answered in 2 hours (120 minutes). The three sections are: Verbal Reasoning (20 questions — analogies, antonyms, sentence completion, reading comprehension), Quantitative Reasoning (20 questions — arithmetic, algebra, geometry, data interpretation), and Analytical/Logical Reasoning (20 questions — logical deductions, critical reasoning, analytical reasoning). There is no negative marking in GAT. The total score is reported out of 100. GAT is conducted paper-based at NTS-designated test centres. The test is available in both English and Urdu medium.' },
    { question: 'What score do I need on GAT for university admission?', answer: 'A GAT score of 60+ out of 100 is generally required for admission to MS/MPhil programmes at Pakistani universities. For highly competitive programmes (Engineering, Computer Science, Business), a score of 70–80 is preferred. For merit scholarships and fellowship positions, a score above 80 is typically needed. Some universities also calculate a combined admission score using GAT (50% weight) plus the undergraduate GPA (50% weight). GAT scores are valid for 2 years. If you plan to apply for multiple universities, take GAT early enough to submit your scores before admission deadlines.' },
  ],
  'accagl': [
    { question: 'What is ACCAGL and who is it for?', answer: 'ACCAGL (Associate Chartered Accountant of the Association of Chartered Certified Accountants) is the professional accounting qualification awarded by ACCA (Association of Chartered Certified Accountants), a global professional accounting body headquartered in London. ACCA is recognised in over 180 countries and is one of the most widely sought-after international accounting qualifications. The ACCAGL designation signifies that a candidate has completed the ACCA professional-level exams and meets the practical experience requirements. It is particularly valued in Pakistan, the Middle East, Southeast Asia, and Africa for careers in audit, taxation, corporate finance, and financial management.' },
    { question: 'What is the ACCA exam structure?', answer: 'ACCA has three levels: Applied Knowledge (3 papers: Accountant in Business, Management Accounting, Financial Accounting), Applied Skills (6 papers: Corporate and Business Law, Performance Management, Taxation, Financial Reporting, Audit and Assurance, Financial Management), and Strategic Professional (5 papers: Strategic Business Reporting, Strategic Business Leader, plus 3 optional papers). There are 13 exams in total. exams are held quarterly (March, June, September, December) at ACCA-approved test centres. Students can attempt up to 4 papers per sitting. Papers are a mix of computer-based exams (CBE) and written exams.' },
    { question: 'How does ACCA compare to CA and which is better?', answer: 'ACCA and CA (Chartered Accountant) both lead to careers in accounting and finance but differ in focus and geography: ACCA is globally recognised with UK-based syllabus (IFRS/UK GAAP), strong in audit firms and multinational companies worldwide; CA (ICAI in India, ICAP in Pakistan) is locally focused with local accounting standards. ACCA exam pass rates are higher than CA (typically 40–60% per paper vs 5–15% for CA Intermediate). ACCA is easier to qualify faster and offers more international mobility. CA offers deeper local market knowledge and is preferred for domestic roles in taxation and statutory audit. Many professionals pursue both — ACCA for global mobility, CA for local expertise. ACCA membership in Pakistan is growing rapidly in multinational firms.' },
  ],

  'cuet': [
    { question: 'What is the expected CUET 2026 exam date and registration timeline?', answer: 'CUET UG 2026 is expected to be conducted in May–June 2026 by NTA. Registration is expected to open in March–April 2026 on cuet.samarth.ac.in. The exam is conducted online (CBT) in multiple sessions across subjects. Keep checking the official CUET website for the exact schedule.' },
    { question: 'What is the subject combination required for CUET 2026?', answer: 'CUET UG requires candidates to appear for one Language test (compulsory) + Domain Subject tests (based on your undergraduate programme choice) + General Test (for some programmes). For example, if applying for B.Sc. Physics honours, you might take: Language (English), Physics domain subject, and General Test.' },
    { question: 'How is CUET scores used for university admission in 2026?', answer: 'CUET scores are used by all central universities (DU, JNU, BHU, etc.) and many state and private universities for undergraduate admissions. Your CUET percentile score, not raw marks, is used for ranking and seat allocation through the CUET-UG portal. A score above the 80th percentile is generally competitive for top university programmes.' },
    { question: 'What is the CUET 2026 exam pattern?', answer: 'CUET UG has three sections: Section IA (30 languages — candidates pick any one), Section IB (19 special languages), Section II (27 domain-specific subjects — candidates pick up to 6), and Section III (General Test for programmes like B.Com, BA Liberal Arts, etc.). Each subject has 50 questions, 40 of which must be attempted. The exam is conducted online (CBT) in multiple sessions.' },
  ],
  'ssc-cgl': [
    { question: 'What is the expected SSC CGL 2026 exam date and application deadline?', answer: 'SSC CGL 2026 Tier 1 exam is expected to be held in June–July 2026. The official notification (released on ssc.nic.in) typically opens online applications 1–2 months before the exam. The application fee is Rs. 100 for general category; SC/ST/PwD/Ex-Servicemen are exempt.' },
    { question: 'What is the age limit for SSC CGL 2026 posts?', answer: 'The age limit for SSC CGL posts varies: Assistant Section Officer (18–27 years), Income Tax Inspector (18–27), Auditors/Tabulators (18–27), and Upper Division Clerk (18–27). Some posts like Assistant Section Officer in CSS allow 20–30 years. Age relaxation of 3 years for OBC and 5 years for SC/ST applies.' },
    { question: 'What is the exam pattern for SSC CGL Tier 1 2026?', answer: 'SSC CGL Tier 1 is a Computer Based Test with 100 questions in 4 sections: Quantitative Aptitude (25), English Comprehension (25), General Intelligence and Reasoning (25), and General Awareness (25). Total time is 60 minutes. Each correct answer earns 2 marks; 0.50 marks are deducted for each wrong answer. Tier 1 is qualifying in nature — the Tier 2 score determines the final rank.' },
    { question: 'How many tiers does SSC CGL have and what are they?', answer: 'SSC CGL has 4 tiers: Tier 1 — Online MCQ (100 questions, 200 marks, qualifying); Tier 2 — Online MCQ (3 papers: Quantitative Abilities, English Language, Statistics/Economics); Tier 3 — Descriptive (Essay/Letter/Application, 100 marks, offline); Tier 4 — Computer Proficiency Test/DEST (qualifying). Final selection is based on Tier 2 + Tier 3 marks combined.' },
  ],
};